// ─── Host clock: live ticking clock anchored to the DB server's system time ──
function HostClock({ serverTime, serverTz }: { serverTime: string | null | undefined; serverTz?: string | null }) {
  const [, force] = useState(0);
  const mountedAt = useRef(Date.now());
  useEffect(() => {
    if (!serverTime) return;
    mountedAt.current = Date.now();
    const id = setInterval(() => force((n) => n + 1), 1000);
    return () => clearInterval(id);
  }, [serverTime]);

  if (!serverTime) return null;
  // Treat the server wall-clock string as UTC for math, then format in UTC so
  // the displayed time matches the server's clock regardless of browser TZ.
  const baseline = Date.parse(String(serverTime).replace(' ', 'T') + 'Z');
  if (!Number.isFinite(baseline)) return null;
  const d = new Date(baseline + (Date.now() - mountedAt.current));
  const hh = String(d.getUTCHours()).padStart(2, '0');
  const mm = String(d.getUTCMinutes()).padStart(2, '0');
  const ss = String(d.getUTCSeconds()).padStart(2, '0');
  const tz = serverTz ? String(serverTz) : '';
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 3, color: T.textMuted, fontSize: 9, fontVariantNumeric: 'tabular-nums' }} title={`Hora del host${tz ? ` (${tz})` : ''}`}>
      <Clock size={9} style={{ opacity: 0.8 }} />
      <span>{hh}:{mm}:{ss}</span>
      {tz && <span style={{ opacity: 0.6, fontSize: 8 }}>{tz}</span>}
    </div>
  );
}

// ─── Fleet instance line chart (wait / CPU / RAM / executions) ────────────────
function FleetInstanceLineChart({ data, names, highlightId, onLineClick, onLineOpen, chartWindow, valueLabel, formatValue, height = FLEET_CHART_H }: {
  data: any; names: Map<string, string>;
  highlightId: string | null;
  onLineClick: (id: string) => void;
  onLineOpen?: (id: string) => void;
  chartWindow?: string;
  valueLabel: string;
  formatValue?: (v: number) => string;
  height?: number;
}) {
  const { tip, show, hide } = useTooltip();
  const [hovBucket, setHovBucket] = React.useState<number | null>(null);
  const fmtVal = formatValue ?? ((v: number) => v >= 1000 ? `${(v / 1000).toFixed(1)}k` : v.toFixed(1));

  if (!data?.buckets?.length) {
    return (
      <div style={{ height, display: 'flex', alignItems: 'center', justifyContent: 'center', color: T.textMuted, fontSize: 11 }}>
        Sin datos en esta ventana.
      </div>
    );
  }

  const W = 700, H = height, pL = 44, pR = 8, pT = 10, pB = 28;
  const plotW = W - pL - pR, plotH = H - pT - pB;
  const buckets: string[] = data.buckets ?? [];
  const n = buckets.length;
  const yMax = Math.max(data.yMax ?? 1, 1);
  const xStep = Math.max(1, Math.ceil(n / 8));

  const stackedByTs = new Map<string, any[]>();
  (data.stacked ?? []).forEach((row: any) => {
    stackedByTs.set(row.ts, row.segments ?? []);
  });

  const connSeries = new Map<string, number[]>();
  (data.series ?? []).forEach((s: any) => {
    const vals = buckets.map((ts) => {
      const segs: any[] = stackedByTs.get(ts) ?? [];
      const seg = segs.find((x: any) => x.connectionId === s.connectionId);
      return seg ? Number(seg.v) : 0;
    });
    connSeries.set(s.connectionId, vals);
  });

  const xOf = (i: number) => pL + (i / Math.max(n - 1, 1)) * plotW;
  const yOf = (v: number) => pT + plotH - (v / yMax) * plotH;

  const activeConns = (data.series ?? []).filter((s: any) => {
    const vals = connSeries.get(s.connectionId) ?? [];
    return vals.some((v) => v > 0);
  }).slice(0, 10);

  const buildHoverText = (ts: string, bucketIdx: number) => {
    const segs: any[] = stackedByTs.get(ts) ?? [];
    const hour = fmtHourLabel(ts);
    const ranked = [...segs].filter((s) => Number(s.v) > 0).sort((a, b) => b.v - a.v);
    if (!ranked.length) return `${hour} · sin datos`;
    const lines = ranked.slice(0, 6).map((seg) => {
      const cName = (names.get(seg.connectionId) ?? seg.connectionId).slice(0, 18);
      return `${cName}: ${fmtVal(Number(seg.v))}`;
    });
    return `${hour} · ${valueLabel}\n${lines.join('\n')}`;
  };

  return (
    <div style={{ position: 'relative' }}>
      <svg viewBox={`0 0 ${W} ${H}`}
        style={{ width: '100%', height: H, display: 'block' }}
        preserveAspectRatio="xMidYMid meet"
        onMouseLeave={() => { hide(); setHovBucket(null); }}>

        <rect x={0} y={0} width={W} height={H} fill={T.panel} />

        {[0, 0.25, 0.5, 0.75, 1].map((f) => {
          const y = pT + plotH * (1 - f);
          const v = yMax * f;
          return (
            <g key={f}>
              <line x1={pL} y1={y} x2={W - pR} y2={y} stroke={T.borderLight} strokeWidth={1} />
              <text x={pL - 3} y={y + 3} fontSize={7} fill={T.textMuted} textAnchor="end">
                {fmtVal(v)}
              </text>
            </g>
          );
        })}

        {(data.series ?? []).map((s: any) => {
          const vals = connSeries.get(s.connectionId) ?? [];
          if (!vals.some((v) => v > 0)) return null;
          const pts = vals.map((v, i) => `${xOf(i).toFixed(1)},${yOf(v).toFixed(1)}`).join(' ');
          const isHl = highlightId === s.connectionId;
          const isOther = highlightId != null && !isHl;
          return (
            <polyline key={s.connectionId}
              points={pts}
              fill="none"
              stroke={s.color}
              strokeWidth={isHl ? 2.5 : 1.5}
              opacity={isOther ? 0.15 : 0.85}
              style={{ cursor: 'pointer' }}
              onClick={() => onLineClick(s.connectionId)}
            />
          );
        })}

        {hovBucket != null && (
          <line x1={xOf(hovBucket)} y1={pT} x2={xOf(hovBucket)} y2={pT + plotH}
            stroke={T.text} strokeWidth={1} strokeDasharray="3 2" opacity={0.4} />
        )}

        {buckets.map((ts, i) => (
          <rect key={i} x={xOf(i) - (plotW / Math.max(n - 1, 1)) / 2} y={pT} width={plotW / Math.max(n - 1, 1)} height={plotH}
            fill="transparent"
            onMouseEnter={(e) => {
              setHovBucket(i);
              show(e, buildHoverText(ts, i));
            }}
            onClick={() => {
              const segs: any[] = stackedByTs.get(ts) ?? [];
              const topSeg = [...segs].sort((a, b) => b.v - a.v)[0];
              if (topSeg) onLineClick(topSeg.connectionId);
            }}
          />
        ))}

        {buckets.map((ts, i) => {
          if (i % xStep !== 0 && i !== n - 1) return null;
          return (
            <text key={i} x={xOf(i)} y={H - 6} textAnchor="middle" fontSize={7} fill={T.textMuted}>
              {fmtAxisLabel(ts, chartWindow ?? '24h')}
            </text>
          );
        })}
      </svg>
      <Tip tip={tip} multiline />

      {activeConns.length > 0 && (
        <div style={{
          display: 'flex', flexWrap: 'wrap', gap: 4, marginTop: 4, paddingLeft: pL,
          maxHeight: 36, overflow: 'hidden',
        }}>
          {activeConns.map((s: any) => {
            const vals = connSeries.get(s.connectionId) ?? [];
            const peak = Math.max(...vals);
            return (
              <button key={s.connectionId} type="button"
                onClick={() => (onLineOpen ? onLineOpen(s.connectionId) : onLineClick(s.connectionId))}
                style={{
                  display: 'flex', alignItems: 'center', gap: 4, background: 'none',
                  border: `1px solid ${highlightId === s.connectionId ? s.color + '80' : 'transparent'}`,
                  cursor: 'pointer', padding: '1px 5px', fontSize: 10, borderRadius: 4,
                  color: highlightId === s.connectionId ? T.text : T.textSubtle,
                }}>
                <span style={{ width: 14, height: 2, backgroundColor: s.color, display: 'inline-block', borderRadius: 1 }} />
                <span>{(names.get(s.connectionId) ?? s.connectionId).slice(0, 20)}</span>
                <span style={{ color: T.textMuted, fontSize: 9 }}>{fmtVal(peak)}</span>
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
}

