// ─── Trend line chart ─────────────────────────────────────────────────────────
function TrendChart({ data, names, direction, highlightId, onLineClick, onLineOpen, chartWindow }: {
  data: any; names: Map<string, string>;
  direction: 'up' | 'down'; highlightId: string | null; onLineClick: (id: string) => void; onLineOpen?: (id: string) => void;
  chartWindow?: string;
}) {
  const { tip, show, hide } = useTooltip();
  if (!data?.buckets?.length) return null;

  const W = 500, H = FLEET_CHART_H, pL = 40, pR = 8, pT = 10, pB = 28;
  const plotW = W - pL - pR, plotH = H - pT - pB;
  const n = data.buckets.length;
  const yMin = -100, yMax = 400, yRange = yMax - yMin;
  const trends = (data.trends ?? []).filter((t: any) =>
    direction === 'up' ? t.trendingUp : !t.trendingUp,
  );
  const xOf = (i: number) => pL + (i / Math.max(n - 1, 1)) * plotW;
  const yOf = (v: number) => pT + plotH * (1 - (Math.min(Math.max(v, yMin), yMax) - yMin) / yRange);
  const xStep = Math.max(1, Math.ceil(n / 8));

  return (
    <div style={{ position: 'relative' }}>
      <svg viewBox={`0 0 ${W} ${H}`}
        style={{ width: '100%', height: H, display: 'block' }}
        preserveAspectRatio="xMidYMid meet"
        onMouseLeave={hide}>

        <rect x={0} y={0} width={W} height={H} fill={T.panel} />

        <text x={9} y={pT + plotH / 2} fontSize={8} fill={T.textMuted} textAnchor="middle"
          transform={`rotate(-90 9 ${pT + plotH / 2})`}>%</text>

        {[-100, 0, 100, 200, 300, 400].map((v) => {
          const y = yOf(v);
          return (
            <g key={v}>
              <line x1={pL} y1={y} x2={W - pR} y2={y}
                stroke={v === 0 ? T.border : T.borderLight} strokeWidth={v === 0 ? 1.5 : 0.8} />
              <text x={pL - 3} y={y + 3} fontSize={7} fill={T.textMuted} textAnchor="end">{v}</text>
            </g>
          );
        })}

        {data.buckets.map((ts: string, i: number) =>
          i % xStep === 0 ? (
            <text key={ts} x={xOf(i)} y={H - 8} fontSize={7} fill={T.textMuted} textAnchor="middle">
              {fmtAxisLabel(ts, chartWindow ?? '24h')}
            </text>
          ) : null,
        )}

        {trends.map((t: any) => {
          const dim = highlightId && highlightId !== t.connectionId ? 0.15 : 1;
          const pctVals: number[] = t.pctValues ?? (t.pctChange != null ? [0, t.pctChange] : []);
          if (!pctVals.length) return null;
          const pts = pctVals.map((v: number, i: number) => `${xOf(i)},${yOf(v)}`).join(' ');
          const color = t.color ?? (data.series ?? []).find((s: any) => s.connectionId === t.connectionId)?.color ?? '#0ea5e9';
          return (
            <g key={t.connectionId} style={{ cursor: 'pointer' }}
              onClick={() => (onLineOpen ? onLineOpen(t.connectionId) : onLineClick(t.connectionId))}>
              <polyline points={pts} fill="none" stroke={color} strokeWidth={2} opacity={dim} />
              {pctVals.map((v: number, i: number) => (
                <circle key={i} cx={xOf(i)} cy={yOf(v)} r={3.5}
                  fill={color} stroke={T.panel} strokeWidth={1.5} opacity={dim}
                  onMouseEnter={(e) => show(e, `${fmtHourLabel(data.buckets[i])} · ${names.get(t.connectionId) ?? ''}: ${v > 0 ? '+' : ''}${v}%`)}
                />
              ))}
            </g>
          );
        })}
      </svg>
      <Tip tip={tip} />

      <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6, marginTop: 4, paddingLeft: 40, maxHeight: 32, overflow: 'hidden' }}>
        {trends.length === 0
          ? <span style={{ fontSize: 10, color: T.textMuted }}>Sin instancias trending {direction === 'up' ? 'up' : 'down'}.</span>
          : trends.map((t: any) => (
            <button key={t.connectionId} type="button"
              onClick={() => (onLineOpen ? onLineOpen(t.connectionId) : onLineClick(t.connectionId))}
              style={{
                display: 'flex', alignItems: 'center', gap: 4, background: 'none', border: 'none',
                cursor: 'pointer', padding: '1px 4px', fontSize: 10,
                color: highlightId === t.connectionId ? T.text : T.textSubtle,
                fontWeight: highlightId === t.connectionId ? 700 : 400,
              }}>
              <span style={{
                width: 10, height: 10, borderRadius: '50%', backgroundColor: t.color,
                display: 'inline-block', border: `2px solid ${T.panel}`,
                boxShadow: `0 0 0 1.5px ${t.color}`,
              }} />
              {(names.get(t.connectionId) ?? t.connectionId).slice(0, 18)}
            </button>
          ))
        }
      </div>
    </div>
  );
}

