const GAUGE_LEVEL_COLORS: Record<string, string> = {
  critical: T.danger,
  warning: T.warning,
  ok: T.success,
  unknown: T.textMuted,
};

function polarPt(cx: number, cy: number, r: number, deg: number) {
  const rad = (deg * Math.PI) / 180;
  return { x: cx + r * Math.cos(rad), y: cy - r * Math.sin(rad) };
}

function compactNum(v: number): string {
  if (v >= 10000) return `${Math.round(v / 1000)}k`;
  if (v >= 1000) return `${(v / 1000).toFixed(1)}k`;
  return `${Math.round(v)}`;
}

/** Semicircle gauge (180° arc) with the value number in the center and a label below.
 *  value/max drives the fill; level drives the color. */
function Gauge({ value, max, level, unit, label, onClick, title }: {
  value: number | null | undefined; max: number; level: string;
  unit?: string; label?: string; onClick?: () => void; title?: string;
}) {
  const cx = 24, cy = 22, r = 19;
  const num = value == null ? NaN : Number(value);
  const hasValue = Number.isFinite(num);
  const frac = hasValue && max > 0 ? Math.min(1, Math.max(0, num / max)) : 0;
  const color = GAUGE_LEVEL_COLORS[level] ?? T.textMuted;
  const bgPath = `M ${polarPt(cx, cy, r, 180).x} ${polarPt(cx, cy, r, 180).y} A ${r} ${r} 0 0 1 ${polarPt(cx, cy, r, 0).x} ${polarPt(cx, cy, r, 0).y}`;
  const endDeg = 180 - 180 * (frac > 0 ? Math.max(frac, 0.02) : 0);
  const fgEnd = polarPt(cx, cy, r, endDeg);
  const fgPath = frac > 0
    ? `M ${polarPt(cx, cy, r, 180).x} ${polarPt(cx, cy, r, 180).y} A ${r} ${r} 0 0 1 ${fgEnd.x} ${fgEnd.y}`
    : '';
  const numStr = hasValue ? compactNum(num) : '—';
  const numFontSize = numStr.length >= 4 ? 7 : numStr.length === 3 ? 8 : 10;
  const svg = (
    <svg viewBox="0 0 48 36" width={48} height={36} style={{ display: 'block' }}>
      <path d={bgPath} fill="none" stroke={T.border} strokeWidth={3.5} strokeLinecap="round" />
      {fgPath && <path d={fgPath} fill="none" stroke={color} strokeWidth={3.5} strokeLinecap="round" />}
      <text x={cx} y={cy + 2} textAnchor="middle" fontSize={numFontSize} fontWeight={700}
        fill={hasValue ? T.text : T.textMuted} style={{ fontVariantNumeric: 'tabular-nums' }}>
        {numStr}
      </text>
      {unit === '%' && hasValue && (
        <text x={cx + 8} y={cy - 5} textAnchor="start" fontSize={5} fill={T.textMuted}>%</text>
      )}
      {label && (
        <text x={cx} y={34} textAnchor="middle" fontSize={6.5} fontWeight={600}
          fill={T.textMuted} style={{ textTransform: 'uppercase', letterSpacing: '0.04em' }}>
          {label}
        </text>
      )}
    </svg>
  );
  if (!onClick) return <span title={title}>{svg}</span>;
  return (
    <button type="button" title={title} onClick={(e) => { e.stopPropagation(); onClick(); }}
      style={{ background: 'none', border: 'none', padding: 0, cursor: 'pointer', lineHeight: 0 }}>
      {svg}
    </button>
  );
}

// ─── Fleet-wide aggregate + sparkline for status tiles ────────────────────────
function fleetAggregate(chart: any): number[] {
  if (!chart?.buckets) return [];
  const byTs = new Map<string, number>();
  (chart.stacked ?? []).forEach((row: any) => {
    const segs: any[] = row.segments ?? [];
    const sum = segs.reduce((s: number, x: any) => s + Number(x.v ?? 0), 0);
    byTs.set(row.ts, (byTs.get(row.ts) ?? 0) + sum);
  });
  return (chart.buckets as string[]).map((ts) => byTs.get(ts) ?? 0);
}

function Sparkline({ values, color, width = 64, height = 18 }: { values: number[]; color: string; width?: number; height?: number }) {
  if (!values || values.length < 2) {
    return <span style={{ display: 'inline-block', width, height }} />;
  }
  const max = Math.max(...values);
  const min = Math.min(...values);
  const range = max - min || 1;
  const n = values.length;
  const x = (i: number) => (i / (n - 1)) * (width - 2) + 1;
  const y = (v: number) => height - 2 - ((v - min) / range) * (height - 4) - 1;
  const pts = values.map((v, i) => `${x(i).toFixed(1)},${y(v).toFixed(1)}`).join(' ');
  const last = values[n - 1];
  return (
    <svg width={width} height={height} style={{ display: 'block' }}>
      <polyline points={pts} fill="none" stroke={color} strokeWidth={1.4}
        strokeLinejoin="round" strokeLinecap="round" opacity={0.9} />
      <circle cx={x(n - 1)} cy={y(last)} r={1.6} fill={color} />
    </svg>
  );
}

/** Rich, unified status tile: label + sparkline + critical/warning badges + a
 *  3-segment fleet distribution bar (critical / warning / ok). Click to filter. */
function FleetStatusTile({ label, critical, warning, total, spark, sparkColor, selected, onClick, title, icon }:{
  label: string; critical: number; warning: number; total: number;
  spark?: number[]; sparkColor?: string; selected?: boolean; onClick?: () => void; title?: string; icon?: React.ReactNode;
}) {
  const ok = Math.max(0, total - critical - warning);
  const pct = (n: number) => (total > 0 ? (n / total) * 100 : 0);
  const hasIssue = critical > 0 || warning > 0;
  const col = critical > 0 ? T.danger : warning > 0 ? T.warning : T.success;
  return (
    <button type="button" onClick={onClick} disabled={!onClick} title={title}
      style={{
        display: 'flex', flexDirection: 'column', gap: 3, textAlign: 'left',
        minWidth: 104, flex: '1 1 104px', cursor: onClick ? 'pointer' : 'default',
        background: selected ? T.selected : T.panel,
        border: `1px solid ${selected ? T.accent : T.borderLight}`,
        borderRadius: 6, padding: '5px 7px 6px',
        boxShadow: selected ? `0 0 0 1px ${T.accent}` : 'none',
        transition: 'border-color 0.15s, box-shadow 0.15s',
      }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: 4, color: T.textMuted }}>
        {icon && <span style={{ display: 'inline-flex', color: T.accent }}>{icon}</span>}
        <span style={{ fontSize: 8.5, fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.05em' }}>{label}</span>
      </div>
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 6, minHeight: 18 }}>
        {spark && spark.length > 1
          ? <Sparkline values={spark} color={sparkColor ?? col} />
          : <span style={{ fontSize: 10, color: T.textMuted }}>—</span>}
        <div style={{ display: 'flex', alignItems: 'center', gap: 3, marginLeft: 'auto' }}>
          {critical > 0 && <span style={{ fontSize: 9, fontWeight: 700, color: '#fff', background: T.danger, padding: '0 4px', borderRadius: 3 }}>{critical}</span>}
          {warning > 0 && <span style={{ fontSize: 9, fontWeight: 700, color: '#fff', background: T.warning, padding: '0 4px', borderRadius: 3 }}>{warning}</span>}
          {critical === 0 && warning === 0 && (
            <span style={{ fontSize: 9, fontWeight: 700, color: T.success, display: 'inline-flex', alignItems: 'center', gap: 2 }}>
              <CheckCircle2Like /> {ok}
            </span>
          )}
        </div>
      </div>
      {/* 3-segment distribution bar */}
      <div style={{ display: 'flex', height: 3, width: '100%', borderRadius: 2, overflow: 'hidden', background: T.border, gap: 1 }}>
        {critical > 0 && <div style={{ width: `${pct(critical)}%`, background: T.danger }} />}
        {warning > 0 && <div style={{ width: `${pct(warning)}%`, background: T.warning }} />}
        {ok > 0 && <div style={{ width: `${pct(ok)}%`, background: hasIssue ? T.success : T.success, opacity: hasIssue ? 0.5 : 0.85 }} />}
      </div>
    </button>
  );
}

function CheckCircle2Like() {
  return <span style={{ display: 'inline-block', width: 8, height: 8, borderRadius: '50%', background: T.success }} />;
}

function fleetWaitAlertLevel(summary: any): 'critical' | 'warning' | 'ok' {
  if (!summary) return 'ok';
  const aas = Number(summary.aas ?? 0);
  const blocking = Number(summary.blockingChains ?? 0);
  const regr = Number(summary.tuningRegressions ?? 0);
  const cpu = Number(summary.cpuPct ?? 0);
  const ram = Number(summary.ramPct ?? 0);
  const hs = Number(summary.healthScore ?? 100);
  const topWaitClass = String(summary.topWait?.waitClass ?? '').toUpperCase();
  const topWaitTotal = Number(summary.topWait?.total ?? 0);
  const ioAlarm = topWaitClass === 'IO' && topWaitTotal > 15;
  const lockAlarm = (topWaitClass === 'LOCK' || topWaitClass === 'LWLOCK') && topWaitTotal > 5;

  if (blocking > 0 || aas > 5 || regr >= 3 || cpu > 85 || ram > 90 || ioAlarm || lockAlarm) return 'critical';
  if (aas > 1 || regr > 0 || cpu > 70 || ram > 75 || hs < 85 || topWaitTotal > 3) return 'warning';
  return 'ok';
}

const WAIT_CLASS_BAR_COLORS: Record<string, string> = {
  IO: '#ef4444',
  LOCK: '#f97316',
  LWLOCK: '#eab308',
  CPU: '#dc2626',
  SYNCH: '#f59e0b',
  Client: '#64748b',
  Other: '#3b82f6',
};

function WaitMiniSummary({ summary }: { summary: any }) {
  const segments: any[] = summary?.waitBar?.length ? summary.waitBar : [];
  const topWait = summary?.topWait ?? null;
  const blocking = Number(summary?.blockingChains ?? 0);
  const aas = Number(summary?.aas ?? 0);
  const alert = fleetWaitAlertLevel(summary);

  const sum = segments.reduce((s: number, x: any) => s + Number(x.value ?? 0), 0);
  const topClass = topWait?.waitClass ? String(topWait.waitClass).toUpperCase() : '';
  const topVal = Number(topWait?.total ?? 0);
  const topColor = topClass ? (WAIT_CLASS_BAR_COLORS[topClass] ?? T.accent) : (alert === 'critical' ? T.danger : alert === 'warning' ? T.warning : T.accent);

  const fmtWaitVal = (v: number) => {
    if (v >= 1000) return `${(v / 1000).toFixed(1)}k`;
    if (v >= 100) return `${Math.round(v)}`;
    return v.toFixed(v < 10 ? 1 : 0);
  };

  const tipLines = [
    topClass ? `Top wait: ${topClass} · ${fmtWaitVal(topVal)}` : 'Sin waits significativos',
    blocking > 0 ? `Blocking chains: ${blocking}` : 'Sin blocking',
    `AAS (active): ${aas.toFixed(aas < 10 ? 1 : 0)}`,
    alert === 'critical' ? 'Alerta: estado crítico' : alert === 'warning' ? 'Atención: revisar' : 'Estado OK',
  ].join('\n');

  return (
    <div style={{ width: 132, fontSize: 9, lineHeight: 1.1 }} title={tipLines}>
      {/* Stacked distribution by wait class */}
      <div style={{ display: 'flex', height: 6, width: '100%', borderRadius: 2, overflow: 'hidden', background: T.border }}>
        {sum > 0 ? segments.map((seg: any, i: number) => {
          const cls = String(seg.waitClass ?? 'Other').toUpperCase();
          const v = Number(seg.value ?? 0);
          if (v <= 0) return null;
          const w = (v / sum) * 100;
          return (
            <div key={i} style={{ width: `${w}%`, background: WAIT_CLASS_BAR_COLORS[cls] ?? T.accent }} title={`${cls}: ${fmtWaitVal(v)}`} />
          );
        }) : (
          <div style={{ width: '100%', background: alert === 'critical' ? T.danger : alert === 'warning' ? T.warning : T.border, opacity: 0.6 }} />
        )}
      </div>
      {/* Dominant class + value */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 4, marginTop: 2, whiteSpace: 'nowrap' }}>
        <span style={{
          width: 7, height: 7, borderRadius: 2, flexShrink: 0, background: topColor,
          boxShadow: alert === 'critical' ? `0 0 4px ${T.danger}` : undefined,
        }} />
        <span style={{ color: T.textSubtle, fontWeight: 600, fontSize: 9 }}>{topClass || 'idle'}</span>
        {topVal > 0 && <span style={{ color: T.textMuted, fontVariantNumeric: 'tabular-nums' }}>{fmtWaitVal(topVal)}</span>}
        {blocking > 0 && (
          <span style={{
            marginLeft: 'auto', padding: '0 4px', borderRadius: 3, fontSize: 8, fontWeight: 700,
            background: T.danger, color: '#fff',
          }} title={`${blocking} blocking chain${blocking === 1 ? '' : 's'}`}>⛔ {blocking}</span>
        )}
      </div>
    </div>
  );
}


