// @ts-nocheck
import { useQuery } from '@tanstack/react-query';
import { api } from '../lib/api';

/** Run a generic AI analysis (`POST /api/connections/{c}/ai/analysis`) for a
 *  given `kind`. The query is enabled only when `enabled` is true (typically
 *  when the modal opens), never retries, and is cached per (connId, kind, params). */
export function useAiAnalysis(connId, kind, params = {}, enabled = true) {
  return useQuery({
    queryKey: ['ai-analysis', connId, kind, params],
    queryFn: () => api.aiAnalysis(connId, kind, params),
    enabled: enabled && !!connId && !!kind,
    retry: false,
    staleTime: Infinity,
  });
}

/** Cross-connection fleet AI analysis. */
export function useAiFleetAnalysis(connectionIds, params = {}, enabled = true) {
  return useQuery({
    queryKey: ['ai-fleet-analysis', connectionIds, params],
    queryFn: () => api.aiFleetAnalysis(connectionIds, params),
    enabled: enabled && Array.isArray(connectionIds) && connectionIds.length > 0,
    retry: false,
    staleTime: Infinity,
  });
}
