// @ts-nocheck
import { useState } from 'react';
import { Sparkles, RefreshCw, Download } from 'lucide-react';
import { Modal } from '../ui/Modal';
import { AiMarkdown } from './AiMarkdown';
import { useAiFleetAnalysis } from '../../hooks/useAiAnalysis';
import { exportText, exportRowsJson, safeName, stampedName } from '../../lib/export';
import { notify } from '../../lib/notify';
import { isLiteEdition } from '../../lib/config';

interface Props {
  connectionIds: string[];
  params?: any;
  label?: string;
  titleAttr?: string;
  className?: string;
  iconSize?: number;
  disabled?: boolean;
}

/** Cross-connection fleet AI analysis trigger + modal. */
export function AiFleetAnalysisButton({
  connectionIds,
  params = {},
  label = 'AI Analysis',
  titleAttr = 'Analizar la flota con IA (priorización y próximos pasos)',
  className = 'nv-btn !py-0.5 !text-2xs text-violet-300 border-violet-800/60 hover:bg-violet-950/40',
  iconSize = 10,
  disabled = false,
}: Props) {
  const [open, setOpen] = useState(false);
  const { data, isLoading, refetch } = useAiFleetAnalysis(connectionIds, params, open);

  if (isLiteEdition || disabled || !connectionIds || connectionIds.length === 0) return null;

  const baseName = safeName('ai-fleet-analysis', 'ai-fleet-analysis');
  const model = data?.model;

  const onExportMd = () => {
    const meta =
      `# Análisis con IA — Fleet (${connectionIds.length} conexiones)\n\n` +
      `- Model: ${model ?? '—'}\n- Generated: ${new Date().toISOString()}\n\n---\n\n`;
    exportText(meta + String(data?.content ?? ''), stampedName(baseName, 'md'), 'text/markdown;charset=utf-8');
    notify('Análisis exportado a Markdown');
  };
  const onExportJson = () => {
    exportRowsJson(
      {
        exportedAt: new Date().toISOString(),
        connectionIds,
        model: model ?? null,
        elapsedMs: data?.elapsedMs ?? null,
        content: String(data?.content ?? ''),
      },
      stampedName(baseName, 'json'),
    );
    notify('Análisis exportado a JSON');
  };

  return (
    <>
      <button type="button" className={className} title={titleAttr} onClick={() => setOpen(true)}>
        <Sparkles size={iconSize} /> {label}
      </button>
      {open && (
        <Modal title="Análisis con IA — Fleet" onClose={() => setOpen(false)} width="max-w-3xl">
          {isLoading ? (
            <div className="text-2xs text-nv-textMuted py-10 text-center">
              <RefreshCw size={16} className="animate-spin inline mr-2" />
              Analizando la flota con IA… puede tardar 30–60s.
            </div>
          ) : !data ? (
            <div className="text-2xs text-nv-textMuted py-6 text-center">Sin respuesta de IA.</div>
          ) : data.ok === false ? (
            <div className="space-y-3">
              <div className="text-2xs rounded border border-red-800/50 bg-red-950/30 text-red-300 px-3 py-2">
                <strong>IA no disponible:</strong> {String(data.message ?? 'error desconocido')}
              </div>
            </div>
          ) : (
            <div className="space-y-2">
              <div className="flex items-center justify-between gap-2 text-2xs text-nv-textSubtle border-b border-nv-border pb-1.5 shrink-0">
                <span className="flex items-center gap-1.5">
                  <Sparkles size={11} className="text-violet-400" />
                  Fleet · <span className="font-mono text-sky-400">{connectionIds.length} conexiones</span>
                </span>
                <span className="flex items-center gap-2">
                  {model && <span>model: <span className="font-mono text-nv-text">{model}</span></span>}
                  {data.elapsedMs != null && <span>{(Number(data.elapsedMs) / 1000).toFixed(1)}s</span>}
                  <button type="button" className="nv-btn !py-0.5 !text-2xs" onClick={() => refetch()} title="Re-analizar">
                    <RefreshCw size={10} /> Re-analizar
                  </button>
                  <button type="button" className="nv-btn !py-0.5 !text-2xs" onClick={onExportMd} title="Exportar a Markdown">
                    <Download size={10} /> .md
                  </button>
                  <button type="button" className="nv-btn !py-0.5 !text-2xs" onClick={onExportJson} title="Exportar a JSON">
                    <Download size={10} /> .json
                  </button>
                </span>
              </div>
              <div className="max-h-[68vh] overflow-y-auto pr-1">
                <AiMarkdown text={String(data.content ?? '')} />
              </div>
            </div>
          )}
        </Modal>
      )}
    </>
  );
}
