// ── Export utility ────────────────────────────────────────────────────────────
function flattenForCsv(row: any, keys: string[]): string {
  return keys.map((k) => {
    const v = row[k];
    if (v == null) return '';
    const s = typeof v === 'object' ? JSON.stringify(v) : String(v);
    return `"${s.replace(/"/g, '""')}"`;
  }).join(',');
}

function exportData(rows: any[], filename: string, format: 'csv' | 'json') {
  if (!rows.length) return;
  let content = '', mime = '';
  if (format === 'json') {
    content = JSON.stringify(rows, null, 2);
    mime = 'application/json';
  } else {
    const keys = Object.keys(rows[0]);
    content = [keys.map((k) => `"${k}"`).join(','), ...rows.map((r) => flattenForCsv(r, keys))].join('\n');
    mime = 'text/csv';
  }
  const a = document.createElement('a');
  a.href = URL.createObjectURL(new Blob([content], { type: mime }));
  a.download = `${filename}.${format === 'json' ? 'json' : 'csv'}`;
  a.click();
}

function ExportMenu({ rows, filename }: { rows: any[]; filename: string }) {
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);
  useEffect(() => {
    const handler = (e: MouseEvent) => { if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false); };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);
  if (!rows?.length) return null;
  return (
    <div ref={ref} style={{ position: 'relative', display: 'inline-block' }}>
      <button type="button" onClick={() => setOpen((x) => !x)}
        className="nv-btn !text-2xs !py-0.5 flex items-center gap-1"
        title="Export data">
        <Download size={11} />Export
      </button>
      {open && (
        <div style={{
          position: 'absolute', right: 0, top: '100%', marginTop: 4, zIndex: 999,
          background: 'var(--nv-toolbar)', border: '1px solid var(--nv-border)',
          borderRadius: 6, padding: '4px 0', minWidth: 120, boxShadow: '0 4px 12px rgba(0,0,0,0.4)',
        }}>
          {[{ fmt: 'csv' as const, icon: <FileText size={11} />, label: 'Export CSV' },
            { fmt: 'json' as const, icon: <FileJson size={11} />, label: 'Export JSON' }].map(({ fmt, icon, label }) => (
            <button key={fmt} type="button"
              onClick={() => { exportData(rows, filename, fmt); setOpen(false); }}
              style={{
                width: '100%', display: 'flex', alignItems: 'center', gap: 8,
                padding: '6px 12px', background: 'none', border: 'none',
                fontSize: 11, color: 'var(--nv-text)', cursor: 'pointer', textAlign: 'left',
              }}
              onMouseEnter={(e) => (e.currentTarget.style.background = 'var(--nv-hover)')}
              onMouseLeave={(e) => (e.currentTarget.style.background = 'none')}>
              {icon}{label}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

