function WaitsPanel({ data, connectionId }: { data: any; connectionId?: string }) {
  const waits: any[] = data?.waits ?? [];
  if (!waits.length) return <Empty msg="No active waits — engine is idle or no wait events captured." />;
  const maxMs = Math.max(...waits.map((w) => Number(w.total_ms ?? w.totalMs ?? 0)), 1);
  return (
    <div>
      <div className="flex items-center justify-between mb-3">
        <p className="text-2xs text-nv-textMuted">Engine: <span className="text-sky-400 font-medium">{data?.engine ?? '—'}</span></p>
        <div className="flex items-center gap-2">
          <ExportButtons rows={waits} filenamePrefix={`live-waits`} />
          {connectionId && (
            <AiAnalysisButton
              connectionId={connectionId}
              kind="live-waits"
              identifier="live-waits"
              title="Análisis con IA — Live Waits"
              titleAttr="Analizar los waits en vivo con IA (triage del bottleneck actual)"
            />
          )}
        </div>
      </div>
      <table className="w-full text-2xs">
        <thead>
          <tr className="text-nv-textSubtle border-b border-nv-border">
            <th className="text-left py-1 pr-2 font-medium">Wait Class</th>
            <th className="text-left py-1 pr-2 font-medium">Wait Event</th>
            <th className="text-right py-1 pr-2 font-medium">Count</th>
            <th className="text-right py-1 pr-3 font-medium">Total</th>
            <th className="text-left py-1 font-medium w-24">Distribution</th>
          </tr>
        </thead>
        <tbody>
          {waits.map((w, i) => {
            const cls = w.wait_class ?? w.waitClass ?? '';
            const ms = Number(w.total_ms ?? w.totalMs ?? 0);
            const pct = (ms / maxMs) * 100;
            return (
              <tr key={i} className="border-b border-nv-border/40 hover:bg-nv-surface">
                <td className="py-1.5 pr-2">
                  <span className={`inline-block w-1.5 h-1.5 rounded-full mr-1 ${waitColor(cls)}`} />
                  <span className="text-nv-text">{cls || '—'}</span>
                </td>
                <td className="py-1.5 pr-2 text-nv-textMuted font-mono">{w.wait_type ?? w.waitType ?? '—'}</td>
                <td className="py-1.5 pr-2 text-right text-nv-textMuted">{fmtNum(w.count ?? 0)}</td>
                <td className="py-1.5 pr-3 text-right text-sky-300">{fmtMs(ms)}</td>
                <td className="py-1.5">
                  <div className="h-2 bg-nv-border rounded-full overflow-hidden">
                    <div className={`h-full ${waitColor(cls)} rounded-full`} style={{ width: `${pct}%` }} />
                  </div>
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

