function AnomaliesPanel({ connectionId }: { connectionId: string }) {
  const q = useQuery({
    queryKey: ['dpa-anomalies', connectionId],
    queryFn: () => api.dpaAnomalies(connectionId),
    staleTime: 60000,
    refetchInterval: DPA_SLOW_REFETCH_MS,
  });
  const items: any[] = q.data?.anomalies ?? [];
  if (q.isLoading) return <Loading />;
  if (!items.length) return <Empty msg="No anomalies vs baseline (DOW+hour, 28d)." />;

  const exportRows = items.map((a) => ({
    type: a.type ?? '',
    detail: a.queryText ?? a.waitType ?? '',
    current: a.currentAvgSec ?? a.latest ?? '',
    baseline: a.baselineAvgSec ?? a.baseline ?? '',
    deviationPct: a.deviationPct ?? '',
  }));

  return (
    <div className="space-y-3">
      <div style={{ display: 'flex', alignItems: 'center', gap: 8, justifyContent: 'space-between' }}>
        <span style={{ fontSize: 12, fontWeight: 600, color: 'var(--nv-text)' }}>
          🔍 {items.length} anomal{items.length === 1 ? 'y' : 'ies'} detected
        </span>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <AiAnalysisButton
            connectionId={connectionId}
            kind="anomalies"
            identifier="anomalies"
            title="Análisis con IA — Anomalies"
            titleAttr="Analizar las anomalías con IA (RCA estadístico)"
          />
          <ExportMenu rows={exportRows} filename="dpa-anomalies" />
        </div>
      </div>
      <div style={{ background: 'var(--nv-surface)', border: '1px solid var(--nv-border)', borderRadius: 8, overflow: 'hidden' }}>
        {items.map((a, i) => {
          const current = Number(a.currentAvgSec ?? a.latest ?? 0);
          const baseline = Number(a.baselineAvgSec ?? a.baseline ?? 1);
          const deviation = baseline > 0 ? ((current - baseline) / baseline * 100) : 0;
          const devColor = deviation > 200 ? '#ef4444' : deviation > 100 ? '#f97316' : '#eab308';
          return (
            <div key={i} style={{ padding: '10px 14px', borderBottom: i < items.length - 1 ? '1px solid var(--nv-border)' : 'none' }}
              onMouseEnter={(el) => { (el.currentTarget as HTMLDivElement).style.background = 'var(--nv-hover)'; }}
              onMouseLeave={(el) => { (el.currentTarget as HTMLDivElement).style.background = 'none'; }}>
              <div style={{ display: 'flex', alignItems: 'flex-start', gap: 12 }}>
                <span style={{
                  fontSize: 10, fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.05em',
                  color: '#f97316', background: '#f9731618', border: '1px solid #f9731640',
                  padding: '2px 8px', borderRadius: 10, flexShrink: 0, marginTop: 2,
                }}>{a.type}</span>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <p style={{ fontSize: 12, fontFamily: 'monospace', color: 'var(--nv-text)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                    {a.queryText ?? a.waitType ?? '—'}
                  </p>
                  <div style={{ display: 'flex', gap: 16, marginTop: 4, flexWrap: 'wrap' }}>
                    <span style={{ fontSize: 11, color: 'var(--nv-textMuted)' }}>
                      Baseline: <span style={{ fontFamily: 'monospace', color: 'var(--nv-textSubtle)' }}>{typeof baseline === 'number' ? baseline.toFixed(4) : baseline}s</span>
                    </span>
                    <span style={{ fontSize: 11, color: 'var(--nv-textMuted)' }}>
                      Current: <span style={{ fontFamily: 'monospace', color: '#ef4444' }}>{typeof current === 'number' ? current.toFixed(4) : current}s</span>
                    </span>
                  </div>
                </div>
                <span style={{ fontSize: 15, fontWeight: 800, fontFamily: 'monospace', color: devColor, flexShrink: 0 }}>
                  +{Math.round(deviation)}%
                </span>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

