function SessionsPanel({ connectionId }: { connectionId: string }) {
  const qc = useQueryClient();
  const [capturing, setCapturing] = useState(false);
  const [capturedAt, setCapturedAt] = useState<Date | null>(null);
  const q = useQuery({
    queryKey: ['dpa-sessions', connectionId],
    queryFn: () => api.dpaSessions(connectionId),
    staleTime: 15000,
    refetchInterval: DPA_REFETCH_MS,
  });
  const rows: any[] = q.data ?? [];

  async function capture() {
    setCapturing(true);
    try {
      await api.dpaSessionsCapture(connectionId);
      qc.invalidateQueries({ queryKey: ['dpa-sessions', connectionId] });
      setCapturedAt(new Date());
    } finally {
      setCapturing(false);
    }
  }

  const activeRows = rows.filter((r) => (r.state ?? '').toLowerCase() !== 'sleep');
  const sleepRows = rows.filter((r) => (r.state ?? '').toLowerCase() === 'sleep');

  return (
    <div className="space-y-3">
      <div className="flex items-center gap-2 flex-wrap">
        <button type="button" className="nv-btn !text-2xs" disabled={capturing} onClick={capture}>
          <RefreshCw size={10} className={`inline mr-1 ${capturing ? 'animate-spin' : ''}`} />
          {capturing ? 'Capturing…' : 'Refresh'}
        </button>
        <AiAnalysisButton
          connectionId={connectionId}
          kind="processlist"
          identifier="sessions"
          title="Análisis con IA — Sessions"
          titleAttr="Analizar las sesiones con IA (triage y recomendaciones)"
        />
        <ExportButtons rows={rows} filenamePrefix={`dpa-sessions`} />
        <span className="text-2xs text-nv-textMuted">
          {rows.length} connections ({activeRows.length} active, {sleepRows.length} idle)
        </span>
        {capturedAt && <span className="text-2xs text-nv-textMuted ml-auto">Captured at {capturedAt.toLocaleTimeString()}</span>}
      </div>
      {q.isLoading || capturing ? <Loading /> : rows.length === 0 ? (
        <div className="text-center py-8 space-y-2">
          <p className="text-nv-textMuted text-sm">No connections visible in processlist.</p>
          <p className="text-2xs text-nv-textSubtle">This may mean all connections are in Sleep state or the monitor user lacks PROCESS privilege.</p>
          <button type="button" className="nv-btn !text-2xs mt-2" onClick={capture}>Try again</button>
        </div>
      ) : (
        <div className="overflow-auto max-h-[28rem]">
          <table className="w-full text-2xs border-collapse">
            <thead className="sticky top-0 z-10">
              <tr className="bg-nv-gridHeader border-b border-nv-border text-nv-textMuted">
                <th className="text-left py-1.5 px-2 font-semibold">PID</th>
                <th className="text-left py-1.5 px-2 font-semibold">User</th>
                <th className="text-left py-1.5 px-2 font-semibold">Host</th>
                <th className="text-left py-1.5 px-2 font-semibold">App/DB</th>
                <th className="text-left py-1.5 px-2 font-semibold">State</th>
                <th className="text-left py-1.5 px-2 font-semibold">Query</th>
              </tr>
            </thead>
            <tbody>
              {rows.map((r, i) => {
                const isActive = (r.state ?? '').toLowerCase() !== 'sleep';
                return (
                  <tr key={i} className="border-b border-nv-border/30 hover:bg-nv-surface/40"
                    style={{ opacity: isActive ? 1 : 0.6 }}>
                    <td className="py-1.5 px-2 font-mono text-nv-textSubtle">{r.sessionId}</td>
                    <td className="py-1.5 px-2 font-medium text-nv-text">{r.userName ?? '—'}</td>
                    <td className="py-1.5 px-2 text-nv-textMuted text-[10px]">{r.hostName ?? '—'}</td>
                    <td className="py-1.5 px-2 text-nv-textSubtle">{r.application ?? '—'}</td>
                    <td className="py-1.5 px-2">
                      <span className={`inline-block px-1.5 py-0.5 rounded text-[9px] font-semibold ${
                        isActive ? 'bg-orange-900/40 text-orange-300' : 'bg-nv-surface/60 text-nv-textMuted'
                      }`}>{r.state ?? 'Sleep'}</span>
                    </td>
                    <td className="py-1.5 px-2 font-mono text-[10px] text-nv-textMuted truncate max-w-xs" title={r.query ?? ''}>
                      {r.query || <span className="text-nv-border">—</span>}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

