const WAIT_BAR_COLORS: Record<string, string> = {
  CPU: '#ef4444', Lock: '#f97316', LWLock: '#eab308', IO: '#3b82f6',
  Client: '#9ca3af', Other: '#0ea5e9',
};

function WaitStackBar({ waits }: { waits: any[] }) {
  const total = waits.reduce((s, w) => s + Number(w.pct ?? 0), 0) || 1;
  return (
    <div className="flex h-3 rounded overflow-hidden bg-nv-border/30 min-w-[120px]">
      {waits.map((w, i) => (
        <div key={i} title={`${w.waitClass}: ${w.pct}%`}
          style={{ width: `${Math.max(0, (Number(w.pct ?? 0) / total) * 100)}%`, background: WAIT_BAR_COLORS[w.waitClass] ?? '#64748b' }} />
      ))}
    </div>
  );
}

const WAIT_CLASS_META: Record<string, { color: string; icon: string; label: string }> = {
  Lock:      { color: '#f97316', icon: '🔒', label: 'Locks' },
  IO:        { color: '#3b82f6', icon: '💾', label: 'I/O' },
  CPU:       { color: '#ef4444', icon: '🔥', label: 'CPU' },
  LWLock:    { color: '#eab308', icon: '⚡', label: 'LWLock' },
  Client:    { color: '#9ca3af', icon: '🔌', label: 'Client' },
  IPC:       { color: '#06b6d4', icon: '📡', label: 'IPC' },
  Timeout:   { color: '#f43f5e', icon: '⏱️', label: 'Timeout' },
  Extension: { color: '#22c55e', icon: '🔧', label: 'Extension' },
  Activity:  { color: '#64748b', icon: '📋', label: 'Activity' },
  Other:     { color: '#8b5cf6', icon: '•', label: 'Other' },
};

function waitClassColor(name: string, index: number): string {
  return WAIT_CLASS_META[name]?.color ?? ['#0ea5e9','#8b5cf6','#14b8a6','#f59e0b','#ec4899','#10b981'][index % 6];
}

function WaitAnalysisPanel({ connectionId, connectionName, active = true }: { connectionId: string; connectionName?: string; active?: boolean }) {
  const [dimension, setDimension] = useState<'query' | 'database' | 'user'>('query');
  const [window, setWindow] = useState('24h');
  const [openingId, setOpeningId] = useState<string | null>(null);
  const [search, setSearch] = useState('');
  const q = useQuery({
    queryKey: ['dpa-wait-analysis', connectionId, dimension, window],
    queryFn: () => api.dpaWaitAnalysis(connectionId, dimension, window, 50),
    enabled: active,
    staleTime: 30000,
    refetchInterval: active ? DPA_REFETCH_MS : false,
  });
  const allEntities: any[] = q.data?.entities ?? [];
  const entities = search
    ? allEntities.filter((e) => String(e.label ?? '').toLowerCase().includes(search.toLowerCase()))
    : allEntities;

  // Summary metrics
  const totalSamples = allEntities.reduce((s, e) => s + (e.totalSamples ?? 0), 0);
  const waitClassTotals: Record<string, number> = {};
  for (const e of allEntities) {
    for (const w of (e.waits ?? [])) {
      waitClassTotals[w.waitClass] = (waitClassTotals[w.waitClass] ?? 0) + (w.samples ?? 0);
    }
  }
  const topClass = Object.entries(waitClassTotals).sort((a, b) => b[1] - a[1])[0];
  const topEntity = allEntities[0];

  function entityOpenKey(entity: any) {
    return String(entity?.id ?? entity?.queryId ?? '');
  }

  function openInQueryStore(entity: any) {
    if (!entity || dimension !== 'query') return;
    const qid = entity.queryId ?? entity.id ?? null;
    const sql = String(entity.sqlText ?? entity.label ?? '').trim();
    const key = entityOpenKey(entity);
    setOpeningId(key);
    try {
      useQueryStoreNavStore.getState().openQuery({ connectionId, queryId: qid, sqlText: sql });
      openQueryStoreWorkspaceTab({ connectionId, connectionName, title: 'Query Store · Wait Analysis' });
    } finally {
      setTimeout(() => setOpeningId(null), 300);
    }
  }

  const exportRows = entities.map((e) => ({
    entity: e.label ?? e.id,
    totalSamples: e.totalSamples ?? 0,
    topWaitClass: (e.waits ?? [])[0]?.waitClass ?? '',
    ...Object.fromEntries((e.waits ?? []).map((w: any) => [w.waitClass, w.pct + '%'])),
  }));

  return (
    <div className="space-y-4">
      {/* Controls */}
      <div className="flex gap-1 flex-wrap items-center">
        <span className="text-2xs text-nv-textSubtle mr-1">Dimension:</span>
        {(['query', 'database', 'user'] as const).map((d) => (
          <button key={d} type="button"
            className={`nv-btn !text-2xs ${dimension === d ? 'bg-sky-900/40 text-sky-300 ring-1 ring-sky-700/40' : ''}`}
            onClick={() => setDimension(d)}>
            {d === 'query' ? '📋 Query' : d === 'database' ? '🗄️ Database' : '👤 User'}
          </button>
        ))}
        <span className="w-px h-4 bg-nv-border mx-1" />
        <span className="text-2xs text-nv-textSubtle mr-1">Window:</span>
        {['1h', '6h', '24h', '7d', '30d'].map((w) => (
          <button key={w} type="button"
            className={`nv-btn !text-2xs ${window === w ? 'bg-violet-900/40 text-violet-300 ring-1 ring-violet-700/40' : ''}`}
            onClick={() => setWindow(w)}>{w}</button>
        ))}
        <div className="ml-auto flex items-center gap-2">
          <AiAnalysisButton
            connectionId={connectionId}
            kind="wait-analysis"
            params={{ dimension, window, limit: 50 }}
            identifier={`wait-analysis-${dimension}`}
            title="Análisis con IA — Wait Analysis"
            titleAttr="Analizar los waits con IA (root-cause por dimensión)"
          />
          <ExportMenu rows={exportRows} filename={`wait-analysis-${dimension}-${window}`} />
        </div>
      </div>

      {q.isLoading ? <Loading /> : allEntities.length === 0 ? (
        <Empty msg="No wait samples yet for this window. Run a snapshot or select a wider time range." />
      ) : (
        <>
          {/* Summary cards */}
          <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
            <StatCard label="Total wait samples" value={fmtNum(totalSamples)}
              icon={<Activity size={14} />} color="#0ea5e9"
              sub={`${allEntities.length} ${dimension}s with waits`} />
            {topClass && (
              <StatCard label="Top wait class" value={topClass[0]}
                icon={<span style={{ fontSize: 14 }}>{WAIT_CLASS_META[topClass[0]]?.icon ?? '•'}</span>}
                color={waitClassColor(topClass[0], 0)}
                sub={`${fmtNum(topClass[1])} samples`} />
            )}
            {topEntity && (
              <StatCard label={`Highest wait ${dimension}`}
                value={String(topEntity.label ?? '').slice(0, 28) || '—'}
                icon={<AlertTriangle size={14} />} color="#f97316"
                sub={`${fmtNum(topEntity.totalSamples ?? 0)} samples`} />
            )}
          </div>

          {/* Wait class breakdown bar */}
          {Object.keys(waitClassTotals).length > 0 && (
            <div style={{
              background: 'var(--nv-surface)', border: '1px solid var(--nv-border)',
              borderRadius: 8, padding: '12px 16px',
            }}>
              <p style={{ fontSize: 11, fontWeight: 600, color: 'var(--nv-text)', marginBottom: 8 }}>Wait Class Distribution</p>
              <div style={{ display: 'flex', height: 20, borderRadius: 4, overflow: 'hidden', marginBottom: 8 }}>
                {Object.entries(waitClassTotals).sort((a, b) => b[1] - a[1]).map(([cls, count], i) => {
                  const pct = totalSamples > 0 ? (count / totalSamples) * 100 : 0;
                  if (pct < 0.5) return null;
                  return (
                    <div key={cls} style={{ width: `${pct}%`, background: waitClassColor(cls, i), position: 'relative' }}
                      title={`${cls}: ${pct.toFixed(1)}% (${fmtNum(count)} samples)`} />
                  );
                })}
              </div>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 10 }}>
                {Object.entries(waitClassTotals).sort((a, b) => b[1] - a[1]).map(([cls, count], i) => {
                  const pct = totalSamples > 0 ? (count / totalSamples) * 100 : 0;
                  return (
                    <div key={cls} style={{ display: 'flex', alignItems: 'center', gap: 5, fontSize: 11 }}>
                      <span style={{ width: 10, height: 10, borderRadius: 2, background: waitClassColor(cls, i), display: 'inline-block', flexShrink: 0 }} />
                      <span style={{ color: 'var(--nv-text)', fontWeight: 500 }}>{cls}</span>
                      <span style={{ color: 'var(--nv-textMuted)' }}>{pct.toFixed(1)}%</span>
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {/* Search + table */}
          <div style={{ background: 'var(--nv-surface)', border: '1px solid var(--nv-border)', borderRadius: 8 }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '10px 14px', borderBottom: '1px solid var(--nv-border)' }}>
              <Search size={13} style={{ color: 'var(--nv-textMuted)', flexShrink: 0 }} />
              <input value={search} onChange={(e) => setSearch(e.target.value)}
                placeholder={`Search ${dimension}s…`}
                style={{
                  flex: 1, background: 'none', border: 'none', outline: 'none',
                  fontSize: 12, color: 'var(--nv-text)',
                }}
              />
              <span style={{ fontSize: 10, color: 'var(--nv-textMuted)' }}>{entities.length} / {allEntities.length}</span>
            </div>
            <div style={{ maxHeight: '28rem', overflowY: 'auto' }}>
              {entities.map((e: any, ei: number) => {
                const maxSamples = allEntities[0]?.totalSamples ?? 1;
                const barPct = Math.min(100, ((e.totalSamples ?? 0) / Math.max(maxSamples, 1)) * 100);
                return (
                  <div key={e.id ?? ei}
                    onClick={() => openInQueryStore(e)}
                    style={{
                      padding: '10px 14px', borderBottom: '1px solid var(--nv-border)', cursor: dimension === 'query' ? 'pointer' : 'default',
                      position: 'relative', overflow: 'hidden',
                    }}
                    onMouseEnter={(el) => { (el.currentTarget as HTMLDivElement).style.background = 'var(--nv-hover)'; }}
                    onMouseLeave={(el) => { (el.currentTarget as HTMLDivElement).style.background = 'none'; }}>
                    {/* Background impact bar */}
                    <div style={{
                      position: 'absolute', left: 0, top: 0, bottom: 0,
                      width: `${barPct}%`, background: 'var(--nv-accent)', opacity: 0.04, pointerEvents: 'none',
                    }} />
                    <div style={{ display: 'flex', alignItems: 'flex-start', gap: 12, position: 'relative' }}>
                      {/* Rank */}
                      <span style={{ fontSize: 10, color: 'var(--nv-textSubtle)', width: 18, flexShrink: 0, paddingTop: 2, textAlign: 'right' }}>
                        #{ei + 1}
                      </span>
                      {/* Label + wait bar */}
                      <div style={{ flex: 1, minWidth: 0 }}>
                        <p style={{ fontSize: 12, fontFamily: 'monospace', color: 'var(--nv-text)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', marginBottom: 5 }}
                          title={e.label}>{e.label}</p>
                        {/* Stacked wait bar */}
                        <div style={{ display: 'flex', height: 6, borderRadius: 3, overflow: 'hidden', background: 'var(--nv-border)', marginBottom: 5 }}>
                          {(e.waits ?? []).map((w: any, wi: number) => (
                            <div key={wi}
                              style={{ width: `${Math.max(0, w.pct ?? 0)}%`, background: waitClassColor(w.waitClass, wi) }}
                              title={`${w.waitClass}: ${w.pct}%`} />
                          ))}
                        </div>
                        {/* Wait class pills */}
                        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 4 }}>
                          {(e.waits ?? []).slice(0, 5).map((w: any, wi: number) => (
                            <span key={wi} style={{
                              display: 'inline-flex', alignItems: 'center', gap: 3,
                              padding: '1px 6px', borderRadius: 10, fontSize: 10,
                              background: waitClassColor(w.waitClass, wi) + '22',
                              color: waitClassColor(w.waitClass, wi),
                              border: `1px solid ${waitClassColor(w.waitClass, wi)}44`,
                            }}>
                              <span style={{ width: 6, height: 6, borderRadius: '50%', background: waitClassColor(w.waitClass, wi), display: 'inline-block' }} />
                              {w.waitClass} {w.pct?.toFixed(1)}%
                            </span>
                          ))}
                        </div>
                      </div>
                      {/* Samples + action */}
                      <div style={{ textAlign: 'right', flexShrink: 0 }}>
                        <div style={{ fontSize: 13, fontWeight: 700, fontFamily: 'monospace', color: 'var(--nv-text)' }}>{fmtNum(e.totalSamples ?? 0)}</div>
                        <div style={{ fontSize: 9, color: 'var(--nv-textSubtle)' }}>samples</div>
                        {dimension === 'query' && (
                          <div style={{ fontSize: 9, color: '#38bdf8', marginTop: 4 }}>
                            {openingId === entityOpenKey(e) ? 'Opening…' : '↗ Query Store'}
                          </div>
                        )}
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </>
      )}
    </div>
  );
}

function HourlyTrendsPanel({ connectionId }: { connectionId: string }) {
  const [days, setDays] = useState(7);
  const [metric, setMetric] = useState('dbTimeSec');
  const q = useQuery({
    queryKey: ['dpa-hourly-trends', connectionId, days],
    queryFn: () => api.dpaHourlyTrends(connectionId, days),
    staleTime: 60000,
    refetchInterval: DPA_SLOW_REFETCH_MS,
  });
  const buckets: any[] = q.data?.buckets ?? [];
  const METRICS = [
    { key: 'dbTimeSec', label: 'DB Time', color: '#0ea5e9', unit: 's', fmt: (v: number) => v >= 3600 ? `${(v/3600).toFixed(1)}h` : v >= 60 ? `${(v/60).toFixed(1)}m` : `${v.toFixed(1)}s` },
    { key: 'executions', label: 'Executions', color: '#8b5cf6', unit: '', fmt: fmtNum },
    { key: 'waitSamples', label: 'Waits', color: '#f97316', unit: '', fmt: fmtNum },
    { key: 'cpuPct', label: 'CPU %', color: '#ef4444', unit: '%', fmt: (v: number) => `${v.toFixed(0)}%` },
    { key: 'activeQueries', label: 'Active Q', color: '#22c55e', unit: '', fmt: fmtNum },
  ];
  const m = METRICS.find((x) => x.key === metric) ?? METRICS[0];
  const values = buckets.map((b) => Number(b[metric] ?? 0));
  const maxV = Math.max(...values, 0.001);

  const W = 800, H = 140, pL = 46, pR = 8, pT = 8, pB = 24;
  const plotW = W - pL - pR, plotH = H - pT - pB;
  const barW = Math.max(1, plotW / Math.max(buckets.length, 1));
  const [hov, setHov] = useState<number | null>(null);

  return (
    <div className="space-y-3">
      <div className="flex gap-1 flex-wrap items-center">
        <span className="text-2xs text-nv-textSubtle mr-1">Period:</span>
        {[1, 7, 30, 90].map((d) => (
          <button key={d} type="button" className={`nv-btn !text-2xs ${days === d ? 'bg-sky-900/40 text-sky-300' : ''}`}
            onClick={() => setDays(d)}>{d === 1 ? '24h' : `${d}d`}</button>
        ))}
        <span className="w-px h-4 bg-nv-border mx-1" />
        <span className="text-2xs text-nv-textSubtle mr-1">Metric:</span>
        {METRICS.map((mx) => (
          <button key={mx.key} type="button"
            className={`nv-btn !text-2xs ${metric === mx.key ? 'text-white' : ''}`}
            style={metric === mx.key ? { background: mx.color + '33', borderColor: mx.color + '88' } : {}}
            onClick={() => setMetric(mx.key)}>{mx.label}</button>
        ))}
      </div>
      {q.isLoading ? <Loading /> : buckets.length === 0 ? (
        <Empty msg="No hourly rollups yet — the scheduler collects hourly data at the top of each hour." />
      ) : (
        <div className="border border-nv-border/50 rounded-lg overflow-hidden bg-nv-surface/30">
          <div className="px-3 pt-2 pb-1 flex items-center justify-between border-b border-nv-border/30">
            <span className="text-xs font-medium text-nv-text">{m.label} — last {days === 1 ? '24 hours' : `${days} days`}</span>
            <span className="text-2xs text-nv-textSubtle">{buckets.length} hourly buckets</span>
          </div>
          <div style={{ position: 'relative' }}>
            <svg viewBox={`0 0 ${W} ${H}`} style={{ width: '100%', height: H + 'px', display: 'block' }}>
              <rect x={0} y={0} width={W} height={H} fill="transparent" />
              {[0, 0.25, 0.5, 0.75, 1].map((f) => {
                const y = pT + plotH * (1 - f);
                return (
                  <g key={f}>
                    <line x1={pL} y1={y} x2={W - pR} y2={y} stroke="#1e293b" strokeWidth={1} />
                    <text x={pL - 4} y={y + 3} textAnchor="end" fontSize={8} fill="#64748b">
                      {m.fmt(maxV * f)}
                    </text>
                  </g>
                );
              })}
              {buckets.map((b: any, i: number) => {
                const v = Number(b[metric] ?? 0);
                const h = (v / maxV) * plotH;
                const x = pL + i * barW;
                const bw = Math.max(barW * 0.8, 1);
                const isHov = hov === i;
                return (
                  <g key={i} onMouseEnter={() => setHov(i)} onMouseLeave={() => setHov(null)}>
                    <rect x={x + (barW - bw) / 2} y={pT + plotH - h} width={bw} height={Math.max(h, 1)}
                      fill={m.color} opacity={isHov ? 1 : 0.75} rx={1} />
                    {isHov && (
                      <g>
                        <rect x={Math.min(x, W - 120)} y={pT} width={110} height={32} rx={3}
                          fill="#1e293b" stroke="#334155" strokeWidth={1} />
                        <text x={Math.min(x, W - 120) + 6} y={pT + 13} fontSize={9} fill="#94a3b8">
                          {b.bucketHour ? new Date(b.bucketHour).toLocaleString([], { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' }) : ''}
                        </text>
                        <text x={Math.min(x, W - 120) + 6} y={pT + 26} fontSize={10} fill="#f1f5f9" fontWeight={600}>
                          {m.fmt(v)}
                        </text>
                      </g>
                    )}
                  </g>
                );
              })}
              {buckets.filter((_: any, i: number) => i % Math.max(1, Math.ceil(buckets.length / 8)) === 0).map((b: any) => {
                const i = buckets.indexOf(b);
                const x = pL + i * barW + barW / 2;
                const d = new Date(b.bucketHour ?? '');
                return (
                  <text key={i} x={x} y={H - 4} textAnchor="middle" fontSize={8} fill="#475569">
                    {isNaN(d.getTime()) ? '' : d.toLocaleDateString([], { month: 'numeric', day: 'numeric' })}
                  </text>
                );
              })}
            </svg>
          </div>
          {hov == null && (
            <div className="flex justify-between px-3 py-1.5 border-t border-nv-border/30">
              <span className="text-2xs text-nv-textMuted">Avg: {m.fmt(values.reduce((a, v) => a + v, 0) / Math.max(values.length, 1))}</span>
              <span className="text-2xs text-nv-textMuted">Peak: {m.fmt(Math.max(...values))}</span>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

