function DpaStatusBanner({ connectionId, onSnapshot }: { connectionId: string; onSnapshot: () => void }) {
  const q = useQuery({
    queryKey: ['dpa-collector-status', connectionId],
    queryFn: () => api.dpaCollectorStatus(connectionId),
    refetchInterval: 30000,
  });
  const st = q.data?.status ?? 'offline';
  const msg = q.data?.message ?? '';
  if (st === 'healthy') return null;
  const tone = st === 'stale' ? 'border-yellow-700/50 bg-yellow-950/20 text-yellow-200'
    : st === 'unreachable' ? 'border-red-700/50 bg-red-950/20 text-red-200'
      : 'border-orange-700/50 bg-orange-950/20 text-orange-200';
  return (
    <div className={`flex items-center gap-3 px-3 py-2 rounded-lg border ${tone} mb-3`}>
      <Activity size={14} className="shrink-0 opacity-80" />
      <div className="flex-1 min-w-0">
        <p className="text-xs font-medium">Collector {st}</p>
        <p className="text-[10px] opacity-80 truncate">{msg || 'No recent DPA samples — connection may be down or SSL/DNS misconfigured.'}</p>
      </div>
      <button type="button" className="nv-btn !text-2xs shrink-0" onClick={onSnapshot}>
        <RefreshCw size={11} className="inline mr-1" />Snapshot
      </button>
    </div>
  );
}

