function engineBadge(engine: string) {
  const cls = engine === 'postgres' ? 'bg-indigo-900/50 text-indigo-300' : engine === 'mongodb' ? 'bg-emerald-900/50 text-emerald-300' : 'bg-orange-900/50 text-orange-300';
  return <span className={`px-1.5 py-0.5 rounded text-2xs uppercase tracking-wide ${cls}`}>{engine}</span>;
}

/** Mini sparkline — renders wait-sample timeline as area SVG */
function FleetSparkline({ points }: { points: { v: number }[] }) {
  if (!points.length) return <div className="h-10 bg-nv-border/20 rounded" />;
  const W = 160, H = 36;
  const max = Math.max(...points.map((p) => p.v), 0.1);
  const xs = points.map((_, i) => (i / Math.max(points.length - 1, 1)) * W);
  const ys = points.map((p) => H - (p.v / max) * H * 0.9 - 1);
  const line = xs.map((x, i) => `${i === 0 ? 'M' : 'L'}${x.toFixed(1)},${ys[i].toFixed(1)}`).join(' ');
  const area = `${line} L${W},${H} L0,${H} Z`;
  return (
    <svg viewBox={`0 0 ${W} ${H}`} width="100%" height={36} preserveAspectRatio="none" className="block">
      <defs>
        <linearGradient id="spark-grad" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor="#38bdf8" stopOpacity={0.35} />
          <stop offset="100%" stopColor="#38bdf8" stopOpacity={0.04} />
        </linearGradient>
      </defs>
      <path d={area} fill="url(#spark-grad)" />
      <path d={line} fill="none" stroke="#38bdf8" strokeWidth={1.5} />
    </svg>
  );
}

