function computeFleetStatus(fleetMap: Map<string, any>, total: number) {
  let monitoring = 0, waitCritical = 0, waitWarning = 0, cpuCritical = 0, cpuWarning = 0;
  let memCritical = 0, memWarning = 0, blockingTotal = 0;
  for (const [, s] of fleetMap) {
    if (!s?.error) monitoring++;
    const aas = s?.aas ?? 0;
    const cpu = s?.cpuPct ?? 0;
    const ram = s?.ramPct ?? 0;
    if (aas > 5 || (s?.blockingChains ?? 0) > 0) waitCritical++;
    else if (aas > 1) waitWarning++;
    if (cpu > 85) cpuCritical++;
    else if (cpu > 70) cpuWarning++;
    if (ram > 90) memCritical++;
    else if (ram > 75) memWarning++;
    blockingTotal += s?.blockingChains ?? 0;
  }
  return {
    monitoring: { active: monitoring, total },
    waitTime: { critical: waitCritical, warning: waitWarning },
    cpu: { critical: cpuCritical, warning: cpuWarning },
    memory: { critical: memCritical, warning: memWarning },
    blocking: { total: blockingTotal },
  };
}

