function matchesFleetFilter(summary: any, filter: FleetFilter) {
  if (!summary || filter === 'all') return true;
  const aas = summary.aas ?? 0;
  const cpu = summary.cpuPct ?? 0;
  const ram = summary.ramPct ?? 0;
  const blocking = summary.blockingChains ?? 0;
  const regr = summary.tuningRegressions ?? 0;
  if (filter === 'wait_critical') return aas > 5 || blocking > 0;
  if (filter === 'wait_warning') return aas > 1 && aas <= 5 && blocking === 0;
  if (filter === 'cpu_critical') return cpu > 85;
  if (filter === 'cpu_warning') return cpu > 70 && cpu <= 85;
  if (filter === 'memory_critical') return ram > 90;
  if (filter === 'memory_warning') return ram > 75 && ram <= 90;
  if (filter === 'tuning_critical') return regr >= 3;
  if (filter === 'tuning_warning') return regr > 0 && regr < 3;
  if (filter === 'sessions_critical') return aas > 10;
  if (filter === 'sessions_warning') return aas > 3 && aas <= 10;
  if (filter === 'blocking' || filter === 'ag') return blocking > 0;
  return true;
}

