export function DpaHomePanel({
  drillConnectionId,
  drillConnectionName,
  initialDpaTab = 'sql',
  active = true,
}: {
  drillConnectionId?: string;
  drillConnectionName?: string;
  initialDpaTab?: DpaTab;
  active?: boolean;
} = {}) {
  const isStandaloneDrill = !!drillConnectionId;
  const [filter, setFilter] = useState('');
  const [selectedId, setSelectedId] = useState<string | null>(drillConnectionId ?? null);
  const [window, setWindow] = useState<WindowKey>('30m');
  const [dpaTab, setDpaTab] = useState<DpaTab>(initialDpaTab);
  const [trendHighlight, setTrendHighlight] = useState<string | null>(null);
  const [findSqlOpen, setFindSqlOpen] = useState(false);
  const [view, setView] = useState<'grid' | 'drill'>(isStandaloneDrill ? 'drill' : 'grid');
  const [fleetFilter, setFleetFilter] = useState<FleetFilter>('all');
  const [collectorFilter, setCollectorFilter] = useState<CollectorFilter>('all');
  const qc = useQueryClient();
  const drillSplit = useHorizontalSplit('dpa-drill-split-v1', 38, { minPct: 26, maxPct: 52, mobileStack: true });

  const { data: connections = [], isLoading: loadingConnections } = useQuery({
    queryKey: ['connections'],
    queryFn: api.connections,
    staleTime: 30000,
    refetchInterval: active ? DPA_REFETCH_MS : false,
    enabled: active,
  });

  const dpaConnections = useMemo(
    () => connections.filter((c: any) => ['mysql', 'postgres', 'mongodb'].includes(c.engine)),
    [connections],
  );

  // Single batch call for all fleet cards (sparklines + KPIs)
  const connIds = useMemo(() => dpaConnections.map((c: any) => c.id), [dpaConnections]);
  const fleetQuery = useQuery({
    queryKey: ['dpa-fleet-summary', connIds],
    queryFn: () => api.dpaFleetSummary(connIds),
    enabled: active && connIds.length > 0,
    staleTime: 20000,
    refetchInterval: active ? DPA_REFETCH_MS : false,
    ...CACHE_FIRST_QUERY,
  });
  const fleetMap: Map<string, any> = useMemo(() => {
    const m = new Map();
    for (const s of fleetQuery.data ?? []) m.set(s.connectionId, s);
    return m;
  }, [fleetQuery.data]);

  const filtered = useMemo(() => dpaConnections
    .filter((c: any) => !filter || `${c.name} ${c.host} ${c.engine}`.toLowerCase().includes(filter.toLowerCase()))
    .filter((c: any) => matchesFleetFilter(fleetMap.get(c.id), fleetFilter))
    .filter((c: any) => {
      if (collectorFilter === 'all') return true;
      const cs = String(fleetMap.get(c.id)?.collectorStatus ?? 'offline');
      return cs === collectorFilter;
    })
    .sort((a: any, b: any) => {
      const hs = (c: any) => fleetMap.get(c.id)?.healthScore ?? 100;
      return hs(a) - hs(b); // worst first
    }), [dpaConnections, filter, fleetMap, fleetFilter, collectorFilter]);

  const selConn = useMemo(() => {
    if (selectedId) {
      const found = dpaConnections.find((c: any) => c.id === selectedId);
      if (found) return found;
      if (isStandaloneDrill && drillConnectionId === selectedId) {
        return {
          id: drillConnectionId,
          name: drillConnectionName ?? drillConnectionId,
          engine: 'mysql',
          host: '',
          port: 0,
        };
      }
      return filtered[0];
    }
    return filtered[0];
  }, [selectedId, dpaConnections, filtered, isStandaloneDrill, drillConnectionId, drillConnectionName]);

  useEffect(() => {
    setTrendHighlight(null);
  }, [selConn?.id, window, dpaTab]);

  // Deep dive queries for selected instance
  const trends = useQuery({
    queryKey: ['dpa-trends', selConn?.id, window, dpaTab],
    queryFn: () => api.dpaTrends(selConn!.id, window, dpaTab),
    enabled: active && !!selConn && view === 'drill',
    staleTime: 20000,
    refetchInterval: active ? DPA_REFETCH_MS : false,
    retry: 2,
    ...CACHE_FIRST_QUERY,
  });
  const workload = useQuery({
    queryKey: ['dpa-deep-workload', selConn?.id, window],
    queryFn: () => api.dpaWorkload(selConn!.id, window),
    enabled: active && !!selConn && view === 'drill',
    staleTime: 20000,
    refetchInterval: active ? DPA_REFETCH_MS : false,
    ...CACHE_FIRST_QUERY,
  });
  const blocking = useQuery({
    queryKey: ['dpa-deep-blocking', selConn?.id],
    queryFn: () => api.dpaBlocking(selConn!.id),
    enabled: active && !!selConn && view === 'drill',
    staleTime: 15000,
    refetchInterval: active ? DPA_REFETCH_MS : false,
    ...CACHE_FIRST_QUERY,
  });
  const processlist = useQuery({
    queryKey: ['processlist', selConn?.id],
    queryFn: () => api.processlist(selConn!.id),
    enabled: active && !!selConn && view === 'drill',
    staleTime: 15000,
    refetchInterval: active ? DPA_REFETCH_MS : false,
    retry: 1,
  });
  const deepResources = useQuery({
    queryKey: ['dpa-deep-resources', selConn?.id],
    queryFn: () => api.dpaResources(selConn!.id),
    enabled: active && !!selConn && view === 'drill',
    staleTime: 20000,
    refetchInterval: active ? DPA_REFETCH_MS : false,
    ...CACHE_FIRST_QUERY,
  });
  const deepTopSql = useQuery({
    queryKey: ['dpa-deep-top-sql', selConn?.id],
    queryFn: () => api.queryStoreQueries(selConn!.id, 60).then((catalog) => {
      const first = catalog?.queries?.[0];
      return first?.normalizedText ?? first?.sampleText ?? null;
    }),
    enabled: active && !!selConn && view === 'drill',
    staleTime: 30000,
    refetchInterval: active ? DPA_REFETCH_MS : false,
    ...CACHE_FIRST_QUERY,
  });

  function openFull(conn: any) {
    openDbToolBoxTab({
      connectionId: conn.id,
      connectionName: conn.name,
    });
  }

  function openQueryStore(queryId: string, queryLabel: string) {
    if (!selConn || !queryId) return;
    const sql = prettifySql(queryLabel);
    useQueryStoreNavStore.getState().openQuery({ connectionId: selConn.id, queryId, sqlText: sql });
    openQueryStoreWorkspaceTab({ connectionId: selConn.id, connectionName: selConn.name });
  }

  function openWaitDetail(waitClass: string) {
    if (!selConn || !waitClass) return;
    useWorkspaceStore.getState().openTab({
      type: 'waitDetail',
      title: `Wait · ${waitClass} · ${selConn.name}`,
      connectionId: selConn.id,
      connectionName: selConn.name,
      waitClass,
    });
  }

  function handleEntityClick(entityName: string, entityLabel: string) {
    if (dpaTab === 'sql') openQueryStore(entityName, entityLabel);
    else if (dpaTab === 'waits') openWaitDetail(entityName);
  }

  function handleRankingClick(item: { label: string; id?: string }, index: number) {
    const entities = t?.entities ?? t?.waitClasses ?? [];
    const ent = entities[index];
    const id = item.id ?? ent?.name ?? ent?.id;
    const label = prettifySql(item.label ?? ent?.label ?? ent?.name ?? '');
    if (dpaTab === 'sql' && id) openQueryStore(String(id), label);
    else if (dpaTab === 'waits' && (id || label)) openWaitDetail(String(id ?? label));
  }

  function fleetTabToDpaTab(tab?: FleetDrillTab): DpaTab {
    if (!tab || tab === 'resources') return 'sql';
    if (tab === 'blocking') return 'waits';
    return tab as DpaTab;
  }

  function goToFleet() {
    if (isStandaloneDrill) openDpaHomeTab();
    else setView('grid');
  }

  function selectAndDrill(connId: string, tab?: FleetDrillTab) {
    const conn = dpaConnections.find((c: any) => c.id === connId);
    if (!conn) return;
    openDbToolBoxTab({
      connectionId: conn.id,
      connectionName: conn.name ?? drillConnectionName,
      dpaTab: fleetTabToDpaTab(tab),
    });
  }

  async function snapshotSelected() {
    if (!selConn) return;
    await api.dpaSnapshot(selConn.id);
    qc.invalidateQueries({ queryKey: ['dpa-trends', selConn.id] });
    qc.invalidateQueries({ queryKey: ['dpa-deep-workload', selConn.id] });
    qc.invalidateQueries({ queryKey: ['dpa-fleet-summary'] });
    qc.invalidateQueries({ queryKey: ['dpa-fleet-charts'] });
  }

  async function snapshotConn(conn: any) {
    await api.dpaSnapshot(conn.id);
    qc.invalidateQueries({ queryKey: ['dpa-fleet-summary'] });
    qc.invalidateQueries({ queryKey: ['dpa-fleet-charts'] });
    qc.invalidateQueries({ queryKey: ['dpa-fleet-status'] });
  }

  function refreshFleet() {
    qc.invalidateQueries({ queryKey: ['dpa-fleet-summary'] });
    qc.invalidateQueries({ queryKey: ['dpa-fleet-charts'] });
    qc.invalidateQueries({ queryKey: ['dpa-fleet-status'] });
  }

  async function enableQueryStoreAll() {
    const targets = dpaConnections.filter((c: any) => ['mysql', 'postgres'].includes(c.engine));
    if (!targets.length) return;
    await Promise.allSettled(targets.map((c: any) => api.queryStoreEnable(c.id)));
    qc.invalidateQueries({ queryKey: ['dpa-fleet-summary'] });
    qc.invalidateQueries({ queryKey: ['dpa-fleet-status'] });
  }

  if (loadingConnections && !dpaConnections.length) return <Loading />;
  if (!dpaConnections.length && !isStandaloneDrill) return <Empty msg="No hay conexiones MySQL/PostgreSQL para DPA." />;
  if (isStandaloneDrill && !selConn) return <Loading />;

  if (view === 'grid' && !isStandaloneDrill) {
    return (
      <div className="h-full min-h-0 flex flex-col overflow-hidden">
        {/* Live alerts sidebar — position:fixed, visible from fleet home */}
        <AlertsSidebar />
        <DpaFleetHome
          connections={dpaConnections}
          connIds={connIds}
          fleetMap={fleetMap}
          loading={isInitialLoad(fleetQuery.isLoading, fleetQuery.data)}
          nameFilter={filter}
          onNameFilter={setFilter}
          fleetFilter={fleetFilter}
          onFleetFilter={setFleetFilter}
          collectorFilter={collectorFilter}
          onCollectorFilter={setCollectorFilter}
          onSelectInstance={selectAndDrill}
          onOpenDpa={openFull}
          onSnapshot={snapshotConn}
          onRefresh={refreshFleet}
          onEnableQueryStoreAll={enableQueryStoreAll}
        />
      </div>
    );
  }

  const t = trends.data;
  const selSummary = selConn ? fleetMap.get(selConn.id) : null;
  const avgActive = t?.buckets?.length ? (t.totalSamples / t.buckets.length) : 0;
  const topWaitDisplay = dpaTab === 'waits'
    ? (t?.waitClasses?.[0]?.name ?? '—')
    : (selSummary?.topWait?.waitClass ?? t?.entities?.[0]?.dominantWaitClass ?? '—');
  const topSqlLabel = dpaTab === 'sql' && t?.entities?.[0]
    ? prettifySql(t.entities[0].label ?? '').slice(0, 48) || '—'
    : (deepTopSql.data ? prettifySql(deepTopSql.data).slice(0, 48) : '—');
  const latestRes = (deepResources.data?.timeline ?? []).slice(-1)[0];
  const lastCpu = latestRes?.cpuPct != null
    ? Number(latestRes.cpuPct)
    : (t?.buckets?.length ? Number(t.buckets[t.buckets.length - 1]?.cpu ?? 0) : Number(selSummary?.cpuPct ?? 0));
  const workRows: any[] = workload.data?.topByDbTime ?? [];
  const dbTimeWindow = workRows.reduce((s: number, r: any) => s + Number(r.totalDbTime ?? 0), 0);

  return (
    <div className="h-full min-h-0 flex flex-col bg-nv-panel text-xs overflow-hidden">
      <AlertsSidebar />
      {/* top bar */}
      <div className="flex items-center gap-3 px-4 py-2 border-b border-nv-border bg-gradient-to-r from-slate-950 to-sky-950/30 shrink-0">
        <span className="font-bold text-sm text-nv-text">Database Performance Analyzer</span>
        {isStandaloneDrill && selConn ? (
          <span className="text-2xs text-nv-textSubtle truncate">{selConn.name}</span>
        ) : (
          <span className="text-2xs text-nv-textSubtle">{dpaConnections.length} instances</span>
        )}
        <div className="flex items-center gap-1 ml-auto">
          <button type="button" onClick={goToFleet} className="nv-btn !py-0.5 !text-2xs"><ArrowLeft size={11} className="inline mr-1" />Fleet</button>
          {!isStandaloneDrill && (
            <button type="button" className="nv-btn !py-0.5 !text-2xs ml-1" onClick={refreshFleet}><RefreshCw size={11} className="inline" /></button>
          )}
        </div>
      </div>

      {(view === 'drill' || isStandaloneDrill) && selConn && (
        <div className="flex-1 flex flex-col min-w-0 min-h-0">
          {/* instance header */}
          <div className="px-4 py-2 border-b border-nv-border flex items-center gap-2 flex-wrap shrink-0">
            <button type="button" onClick={goToFleet} className="text-nv-textMuted hover:text-sky-300 inline-flex items-center"><ArrowLeft size={11} className="mr-1" />Fleet</button>
            <span className="font-semibold text-nv-text text-sm">{selConn.name}</span>
            {engineBadge(selConn.engine)}
            <span className="text-2xs text-nv-textMuted">{selConn.host}:{selConn.port}</span>
            <div className="ml-auto flex items-center gap-1 flex-wrap">
              {WINDOWS.map((wk) => (
                <button key={wk} type="button" onClick={() => setWindow(wk)}
                  className={`nv-btn !py-0.5 !text-2xs ${window === wk ? 'bg-sky-900/40 text-sky-300' : ''}`}>{wk}</button>
              ))}
              <button type="button" className="nv-btn !py-0.5 !text-2xs ml-1" onClick={snapshotSelected}><RefreshCw size={11} className="inline mr-1" />Snapshot</button>
              <button type="button" className="nv-btn !py-0.5 !text-2xs" onClick={() => openFull(selConn)}>Full DPA ↗</button>
            </div>
          </div>

          <div className="flex-1 min-h-0 overflow-y-auto overflow-x-hidden">
            <div className="px-4 pt-4 pb-6 space-y-4">
            {/* KPI strip */}
            <div>
            <div className="grid grid-cols-2 md:grid-cols-5 gap-2">
              <Metric label="Avg active sessions" value={avgActive.toFixed(2)} tone="sky" />
              <Metric label={dpaTab === 'sql' ? 'Top SQL' : 'Top wait'} value={dpaTab === 'sql' ? (topSqlLabel ?? '—') : topWaitDisplay} tone="orange" />
              <ConnectionBreakdownMetric
                rows={processlist.data ?? []}
                loading={processlist.isLoading}
                onOpenProcesses={() => openProcessListTab({
                  connectionId: selConn.id,
                  connectionName: selConn.name,
                })}
              />
              <Metric label="CPU host" value={`${lastCpu.toFixed(0)}%`} tone={lastCpu > 80 ? 'red' : 'green'} />
              <Metric label={`DB Time (${window})`} value={fmtDbTime(dbTimeWindow)} tone="sky" />
            </div>
            <div className="text-[10px] text-nv-textSubtle mt-1">
              Host telemetry source: {(latestRes?.sourceLabel ?? 'collector')} · if CPU=0 on MySQL it means thread-load estimator is idle.
            </div>
            </div>

            {/* Split: queries LEFT · chart RIGHT */}
            <div
              ref={drillSplit.containerRef}
              className={`flex ${drillSplit.stacked ? 'flex-col' : 'flex-row'} gap-0 min-w-0 ${drillSplit.stacked ? 'h-auto' : 'h-[380px]'}`}
              onMouseLeave={() => setTrendHighlight(null)}
            >
              {/* Left — rankings */}
              <div
                style={drillSplit.stacked ? { width: '100%', flex: '0 0 auto', maxHeight: '44vh' } : { width: `${drillSplit.leftPct}%` }}
                className="min-w-0 flex flex-col border border-nv-border rounded-l-lg p-3 bg-nv-surface/40"
              >
                <div className="font-medium text-nv-text mb-2 shrink-0 text-xs">
                  {dpaTab === 'sql' ? 'Top SQL by Avg Active Sessions'
                    : dpaTab === 'waits' ? 'Top Waits'
                    : `Top ${dpaTab.charAt(0).toUpperCase() + dpaTab.slice(1)}`}
                </div>
                <div className="flex-1 min-h-0 overflow-y-auto pr-1">
                  {dpaTab === 'sql' ? (
                    <SqlRankingTable
                      entities={t?.entities ?? []}
                      onOpen={openQueryStore}
                      highlightEntity={trendHighlight}
                      onHighlightEntity={setTrendHighlight}
                    />
                  ) : (
                    <DimensionBars
                      items={(t?.entities ?? t?.waitClasses?.map((c: any) => ({ ...c, label: c.name, value: c.total })) ?? [])
                        .slice(0, 12)
                        .map((e: any) => ({
                          id: e.name ?? e.id,
                          label: (e.label ?? e.name ?? '').replace(/\s+/g, ' ').slice(0, 80),
                          value: Number(e.total ?? 0),
                          sub: undefined,
                          tone: e.color ?? entityColor(e.name, t?.entities ?? [], dpaTab),
                        }))}
                      emptyMsg={`Sin datos de ${dpaTab}. Toma un snapshot para acumular muestras.`}
                      onItemClick={dpaTab === 'waits' ? handleRankingClick : undefined}
                      highlightEntity={trendHighlight}
                      onHighlightEntity={setTrendHighlight}
                    />
                  )}
                </div>
              </div>

              {/* Resize handle */}
              {!drillSplit.stacked && (
              <div
                role="separator"
                aria-orientation="vertical"
                className="resizer vertical shrink-0 cursor-col-resize bg-nv-border/60 hover:bg-sky-600/50 active:bg-sky-500/70 transition-colors self-stretch"
                onPointerDown={drillSplit.onResizeStart}
                title="Arrastra para redimensionar"
              />
              )}

              {/* Right — trend chart */}
              <div className={`flex-1 min-w-0 flex flex-col border ${drillSplit.stacked ? 'border-t-0 border-nv-border rounded-b-lg mt-2' : 'border-l-0 border-nv-border rounded-r-lg'} p-3 bg-nv-surface/40`}>
                <div className="flex items-center gap-2 mb-2 flex-wrap shrink-0">
                  <span className="font-medium text-nv-text text-xs">Trends</span>
                  {t?.usedQueryStore && (
                    <span className="text-2xs bg-indigo-900/40 text-indigo-300 px-1.5 py-0.5 rounded border border-indigo-700/40">Query Store</span>
                  )}
                  {t?.usedPerQuerySamples && !t?.usedQueryStore && (
                    <span className="text-2xs bg-sky-900/30 text-sky-400 px-1.5 py-0.5 rounded">per-query DPA mode</span>
                  )}
                  {t?.usedFallback && (
                    <span className="text-2xs bg-orange-900/30 text-orange-400 px-1.5 py-0.5 rounded">fallback: DB Time</span>
                  )}
                  {t?.bucket && (
                    <span className="text-2xs text-nv-textSubtle bg-nv-panel/60 px-1.5 py-0.5 rounded border border-nv-border/40" title={t?.samplingNote ?? ''}>
                      {t.bucket} · {t.buckets?.length ?? 0} pts
                    </span>
                  )}
                  <div className="flex gap-1 flex-wrap ml-auto">
                    {DPA_TABS.map((tab) => (
                      <button key={tab.key} type="button" onClick={() => setDpaTab(tab.key)}
                        className={`nv-btn !py-0.5 !text-2xs ${dpaTab === tab.key ? 'bg-sky-900/60 text-sky-200 font-semibold' : ''}`}>
                        {tab.label}
                      </button>
                    ))}
                  </div>
                </div>
                <div className="flex-1 min-h-0 overflow-x-auto overflow-y-hidden">
                  {isInitialLoad(trends.isLoading, trends.data) ? <Loading /> : trends.isError ? (
                    <Empty msg={`Error cargando trends: ${(trends.error as Error)?.message ?? 'desconocido'}. Usa Snapshot o Refresh.`} />
                  ) : (
                    <WaitTrendChart
                      trends={t}
                      onEntityClick={handleEntityClick}
                      highlightEntity={trendHighlight}
                      onHighlightEntity={setTrendHighlight}
                      compact
                    />
                  )}
                </div>
                <p className="text-[10px] text-nv-textSubtle mt-1 shrink-0">
                  Hover → origen · click barra → Query Store
                </p>
              </div>
            </div>

            {/* Lower panels */}
            <div className="space-y-3">
            <div className="border border-nv-border rounded-lg p-3 bg-nv-surface/40">
              <div className="font-medium text-nv-text mb-3">Current Blocking</div>
              {isInitialLoad(blocking.isLoading, blocking.data) ? <Loading /> : blocking.isError ? (
                <Empty msg={`Error cargando blocking: ${(blocking.error as Error)?.message ?? 'desconocido'}`} />
              ) : <BlockingPanel data={blocking.data} />}
            </div>

            {/* Find SQL */}
            <div className="border border-nv-border rounded-lg p-3 bg-nv-surface/40">
              <div className="flex items-center gap-2 mb-2">
                <span className="font-medium text-nv-text">Find SQL</span>
                <button type="button" className="nv-btn !py-0.5 !text-2xs" onClick={() => setFindSqlOpen((o) => !o)}>
                  {findSqlOpen ? 'Close' : 'Search…'}
                </button>
              </div>
              {findSqlOpen && <FindSqlPanel connectionId={selConn.id} onOpenQuery={openQueryStore} />}
            </div>

            {/* Resources */}
            <div className="border border-nv-border rounded-lg p-3 bg-nv-surface/40">
              <div className="font-medium text-nv-text mb-3">Resources</div>
              {isInitialLoad(deepResources.isLoading, deepResources.data) ? <Loading /> : deepResources.isError ? (
                <Empty msg={`Error cargando resources: ${(deepResources.error as Error)?.message ?? 'desconocido'}`} />
              ) : <ResourcesPanel data={deepResources.data} />}
            </div>
            </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// (Metric moved to ./shared/helpers)

// ── snapshot button ───────────────────────────────────────────────────────────

// (SnapshotBtn moved to ./shared/DpaHeader)

// ── main panel ───────────────────────────────────────────────────────────────

export function DpaObservabilityPanel({ connectionId, connectionName, active = true, initialTab = 'overview' }: { connectionId: string; connectionName?: string; active?: boolean; initialTab?: Tab }) {
  const [activeTab, setActiveTab] = useState<Tab>(initialTab);
  const [window, setWindow] = useState<WindowKey>('24h');
  const [trendsChartTab, setTrendsChartTab] = useState<'sql' | 'waits'>('sql');
  const [trendHighlight, setTrendHighlight] = useState<string | null>(null);
  const qc = useQueryClient();

  const trends = useQuery({
    queryKey: ['dpa-trends', connectionId, window, trendsChartTab],
    queryFn: () => api.dpaTrends(connectionId, window, trendsChartTab),
    enabled: active && activeTab === 'trends',
    staleTime: 30000,
    refetchInterval: active && activeTab === 'trends' ? DPA_SLOW_REFETCH_MS : false,
    ...CACHE_FIRST_QUERY,
  });
  const hourly = useQuery({ queryKey: ['dpa-hourly-trends', connectionId], queryFn: () => api.dpaHourlyTrends(connectionId, 7), enabled: false });
  const waitAnalysis = useQuery({ queryKey: ['dpa-wait-analysis', connectionId], queryFn: () => api.dpaWaitAnalysis(connectionId), enabled: false });
  const waits = useQuery({ queryKey: ['dpa-waits', connectionId], queryFn: () => api.dpaWaits(connectionId), enabled: active && activeTab === 'waits', staleTime: 20000, refetchInterval: active && activeTab === 'waits' ? DPA_REFETCH_MS : false });
  const blocking = useQuery({ queryKey: ['dpa-blocking', connectionId], queryFn: () => api.dpaBlocking(connectionId), enabled: active && activeTab === 'blocking', staleTime: 20000, refetchInterval: active && activeTab === 'blocking' ? DPA_REFETCH_MS : false, ...CACHE_FIRST_QUERY });
  const workload = useQuery({
    queryKey: ['dpa-workload', connectionId],
    queryFn: () => api.dpaWorkload(connectionId),
    enabled: active && activeTab === 'workload',
    staleTime: 120_000,
    refetchInterval: active && activeTab === 'workload' ? DPA_SLOW_REFETCH_MS : false,
    retry: 1,
    ...CACHE_FIRST_QUERY,
  });
  const events = useQuery({ queryKey: ['dpa-events', connectionId], queryFn: () => api.dpaEvents(connectionId), enabled: active && activeTab === 'events', staleTime: 20000, refetchInterval: active && activeTab === 'events' ? DPA_REFETCH_MS : false, ...CACHE_FIRST_QUERY });
  const resources = useQuery({ queryKey: ['dpa-resources', connectionId], queryFn: () => api.dpaResources(connectionId), enabled: active && (activeTab === 'resources' || activeTab === 'overview'), staleTime: 20000, refetchInterval: active && (activeTab === 'resources' || activeTab === 'overview') ? DPA_REFETCH_MS : false, ...CACHE_FIRST_QUERY });
  const health = useQuery({ queryKey: ['dpa-health', connectionId], queryFn: () => api.dpaHealth(connectionId), enabled: active && (activeTab === 'health' || activeTab === 'overview'), staleTime: 20000, refetchInterval: active && (activeTab === 'health' || activeTab === 'overview') ? DPA_REFETCH_MS : false, ...CACHE_FIRST_QUERY });
  const capacity = useQuery({ queryKey: ['dpa-capacity', connectionId], queryFn: () => api.dpaCapacity(connectionId), enabled: active && activeTab === 'capacity', staleTime: 30000, refetchInterval: active && activeTab === 'capacity' ? DPA_SLOW_REFETCH_MS : false });
  const alerts = useQuery({ queryKey: ['dpa-alerts', connectionId], queryFn: () => api.dpaAlerts(connectionId), enabled: false });
  const anomalies = useQuery({ queryKey: ['dpa-anomalies', connectionId], queryFn: () => api.dpaAnomalies(connectionId), enabled: false });
  const tableAdvisor = useQuery({ queryKey: ['dpa-table-advisor', connectionId], queryFn: () => api.dpaTableAdvisor(connectionId), enabled: false });
  const sessions = useQuery({ queryKey: ['dpa-sessions', connectionId], queryFn: () => api.dpaSessions(connectionId), enabled: false });

  const tabQueries: Record<string, ReturnType<typeof useQuery>> = {
    trends, waits, blocking, events, resources, health, capacity,
  };
  const activeQuery = tabQueries[activeTab];
  const showTabSpinner = activeQuery && isInitialLoad(activeQuery.isLoading, activeQuery.data)
    && !['overview', 'workload', 'alerts', 'waitAnalysis', 'hourly', 'anomalies', 'advisors', 'sessions', 'logs', 'explain', 'queryStore'].includes(activeTab);

  function refresh() {
    qc.invalidateQueries({ queryKey: ['dpa-trends', connectionId] });
    qc.invalidateQueries({ queryKey: ['dpa-waits', connectionId] });
    qc.invalidateQueries({ queryKey: ['dpa-blocking', connectionId] });
    qc.invalidateQueries({ queryKey: ['dpa-workload', connectionId] });
    qc.invalidateQueries({ queryKey: ['dpa-events', connectionId] });
    qc.invalidateQueries({ queryKey: ['dpa-resources', connectionId] });
    qc.invalidateQueries({ queryKey: ['dpa-health', connectionId] });
    qc.invalidateQueries({ queryKey: ['dpa-capacity', connectionId] });
    qc.invalidateQueries({ queryKey: ['dpa-collector-status', connectionId] });
    qc.invalidateQueries({ queryKey: ['qs-top-dpa', connectionId] });
    qc.invalidateQueries({ queryKey: ['qs-catalog-dpa', connectionId] });
    qc.invalidateQueries({ queryKey: ['qs-status', connectionId] });
  }

  function openQueryStoreTab() {
    openQueryStoreWorkspaceTab({ connectionId, connectionName });
  }

  return (
    <div className="h-full flex flex-col text-xs bg-nv-bg">
      {/* Global live alerts sidebar — position:fixed, always visible while in DPA */}
      <AlertsSidebar />
      {/* header */}
      <div className="px-4 py-2.5 border-b border-nv-border shrink-0" style={{ background: 'var(--nv-dpa-header-bg)' }}>
        <div className="flex items-center gap-2 flex-wrap mb-2">
          <button
            type="button"
            className="nv-btn !py-0.5 !text-2xs"
            onClick={() => useWorkspaceStore.getState().openTab({ type: 'dpaHome', title: 'DPA Home' })}
            title="Back to DPA Home"
          >
            <Home size={11} className="inline mr-1" />Home
          </button>
          <BarChart3 size={16} className="text-sky-400" />
          <span className="font-semibold text-sm text-nv-text">DPA Observability</span>
          {connectionName && <span className="text-nv-textMuted">· {connectionName}</span>}
          <CollectorBadge connectionId={connectionId} />
          <div className="ml-auto flex items-center gap-1">
            {activeTab === 'trends' && WINDOWS.map((wk) => (
              <button key={wk} type="button" onClick={() => setWindow(wk)} className={`nv-btn !py-0.5 !text-2xs ${window === wk ? 'bg-sky-900/40 text-sky-300' : ''}`}>{wk}</button>
            ))}
            {activeTab !== 'explain' && (
              <SnapshotBtn connectionId={connectionId} onDone={refresh} />
            )}
          </div>
        </div>
        {/* Nav — icon tab strip, grouped, horizontally scrollable (unified style) */}
        <div className="flex items-center gap-2 overflow-x-auto nv-tabs-strip mt-2 -mx-1 px-1 pb-1">
          {TAB_GROUPS.map((g, gi) => (
            <div key={g.label} className="flex items-center gap-1 shrink-0">
              {gi > 0 && <span className="w-px h-4 bg-nv-border mx-1 shrink-0" />}
              <span className="text-[9px] uppercase tracking-wider text-nv-textSubtle mr-0.5 shrink-0">{g.label}</span>
              {g.tabs.map((t) => {
                const Icon = TAB_ICONS[t];
                const on = activeTab === t;
                return (
                  <button
                    key={t}
                    type="button"
                    title={TAB_LABELS[t]}
                    onClick={() => setActiveTab(t)}
                    className={`inline-flex items-center gap-1 px-2 py-1 rounded-md text-[10px] whitespace-nowrap transition-colors shrink-0 ${on ? 'bg-sky-600/25 text-sky-200 font-semibold ring-1 ring-sky-600/40' : 'text-nv-textMuted hover:text-nv-text hover:bg-nv-surface/70'}`}
                  >
                    {Icon && <Icon size={11} className={on ? 'text-sky-300' : 'text-nv-textSubtle'} />}
                    {TAB_LABELS[t]}
                  </button>
                );
              })}
            </div>
          ))}
        </div>
      </div>

      {/* body */}
      <div className="flex-1 overflow-auto p-4">
        {showTabSpinner ? (
          <Loading />
        ) : (
          <>
            {activeTab === 'overview' && (
              <DpaOverviewPanel
                connectionId={connectionId}
                connectionName={connectionName}
                onTab={setActiveTab}
                onOpenQueryStore={openQueryStoreTab}
                onSnapshot={refresh}
              />
            )}
            {activeTab === 'queryStore' && <DpaQueryStorePanel connectionId={connectionId} connectionName={connectionName} />}
            {activeTab === 'trends' && (
              <div className="space-y-3">
                <div className="flex items-center gap-2 flex-wrap">
                  <span className="text-2xs text-nv-textSubtle">Vista:</span>
                  {(['sql', 'waits'] as const).map((v) => (
                    <button key={v} type="button"
                      className={`nv-btn !py-0.5 !text-2xs ${trendsChartTab === v ? 'bg-sky-900/40 text-sky-300' : ''}`}
                      onClick={() => { setTrendsChartTab(v); setTrendHighlight(null); }}>
                      {v === 'sql' ? 'Top SQL' : 'Wait classes'}
                    </button>
                  ))}
                </div>
                <WaitTrendChart
                  trends={trends.data}
                  highlightEntity={trendHighlight}
                  onHighlightEntity={setTrendHighlight}
                  onEntityClick={(id, label) => {
                    if (trendsChartTab === 'sql') {
                      useQueryStoreNavStore.getState().openQuery({ connectionId, queryId: id, sqlText: label });
                      openQueryStoreWorkspaceTab({ connectionId, connectionName });
                    } else {
                      setActiveTab('waitAnalysis');
                    }
                  }}
                />
              </div>
            )}
            {activeTab === 'hourly' && <HourlyTrendsPanel connectionId={connectionId} />}
            {activeTab === 'waitAnalysis' && <WaitAnalysisPanel connectionId={connectionId} connectionName={connectionName} active={active} />}
            {activeTab === 'waits' && (
              isInitialLoad(waits.isLoading, waits.data) ? <Loading /> :
              <WaitsPanel data={waits.data} connectionId={connectionId} />
            )}
            {activeTab === 'blocking' && <BlockingPanelWithHistory connectionId={connectionId} data={blocking.data} />}
            {activeTab === 'workload' && (
              isInitialLoad(workload.isLoading, workload.data) ? (
                <div className="space-y-2">
                  <Loading />
                  <p className="text-2xs text-nv-textSubtle text-center">Calculando workload (puede tardar en instancias grandes)…</p>
                </div>
              ) : workload.isError ? (
                <Empty msg={`Error cargando workload: ${(workload.error as Error)?.message ?? 'desconocido'}`} />
              ) : (
                <WorkloadPanel data={workload.data} connectionId={connectionId} connectionName={connectionName} />
              )
            )}
            {activeTab === 'alerts' && <AlertsPanel connectionId={connectionId} connectionName={connectionName} active={active} />}
            {activeTab === 'anomalies' && <AnomaliesPanel connectionId={connectionId} />}
            {activeTab === 'advisors' && <AdvisorsPanel connectionId={connectionId} />}
            {activeTab === 'indexes' && <IndexesPanel connectionId={connectionId} />}
            {activeTab === 'sessions' && <SessionsPanel connectionId={connectionId} />}
            {activeTab === 'events' && <EventsPanel data={events.data} />}
            {activeTab === 'logs' && <LogsPanel connectionId={connectionId} />}
            {activeTab === 'resources' && <ResourcesPanel data={resources.data} />}
            {activeTab === 'health' && <HealthPanel data={health.data} />}
            {activeTab === 'capacity' && <CapacityPanel data={capacity.data} />}
            {activeTab === 'explain' && <ExplainPanel connectionId={connectionId} />}
          </>
        )}
      </div>
    </div>
  );
}

// ── Find SQL panel ─────────────────────────────────────────────────────────────

function FindSqlPanel({ connectionId, onOpenQuery }: { connectionId: string; onOpenQuery?: (id: string, label: string) => void }) {
  const [q, setQ] = useState('');
  const [submitted, setSubmitted] = useState('');
  const results = useQuery({
    queryKey: ['dpa-find-sql', connectionId, submitted],
    queryFn: () => api.dpaFindSql(connectionId, { q: submitted }),
    enabled: true,
    staleTime: 30000,
    refetchInterval: DPA_REFETCH_MS,
  });
  const rows: any[] = results.data?.results ?? [];
  return (
    <div className="space-y-2">
      <div className="flex gap-2">
        <input value={q} onChange={(e) => setQ(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && setSubmitted(q)}
          className="nv-input flex-1 text-2xs" placeholder="Search SQL text… (Enter)" />
        <button type="button" className="nv-btn !text-2xs" onClick={() => setSubmitted(q)}>Search</button>
      </div>
      {results.isLoading && <Loading />}
      {!results.isLoading && rows.length === 0 && <Empty msg="No results. Try a different search or wider date range." />}
      {rows.length > 0 && (
        <div className="space-y-1 max-h-64 overflow-auto">
          {rows.map((r: any) => (
            <button key={r.id} type="button" onClick={() => onOpenQuery?.(r.id, String(r.text ?? '').slice(0, 60))}
              className="w-full text-left px-2 py-1.5 rounded border border-nv-border/50 hover:border-sky-600/60 hover:bg-sky-950/20 group">
              <div className="flex items-center justify-between gap-2">
                <span className="text-2xs font-mono text-nv-text truncate">{String(r.text ?? '').replace(/\s+/g, ' ').slice(0, 100)}</span>
                <span className="text-2xs text-sky-300 font-mono shrink-0">{fmtDbTime(Number(r.totalDbTime ?? 0))}</span>
              </div>
              <div className="flex gap-3 mt-0.5">
                <span className="text-[10px] text-nv-textSubtle">{r.schema}</span>
                <span className="text-[10px] text-nv-textSubtle">{Number(r.totalCalls ?? 0).toLocaleString()} calls</span>
                {r.lastSeen && <span className="text-[10px] text-nv-textSubtle">last: {new Date(r.lastSeen).toLocaleString()}</span>}
              </div>
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

// ── Blocking with history ──────────────────────────────────────────────────────

function BlockingPanelWithHistory({ connectionId, data }: { connectionId: string; data: any }) {
  const [subTab, setSubTab] = useState<'live' | 'history' | 'deadlocks' | 'blockers' | 'heatmap'>('live');
  const history = useQuery({
    queryKey: ['dpa-blocking-records', connectionId],
    queryFn: () => api.dpaBlockingRecords(connectionId, 50),
    enabled: subTab === 'history',
    staleTime: 60000,
    refetchInterval: DPA_SLOW_REFETCH_MS,
  });
  const deadlocks = useQuery({
    queryKey: ['dpa-deadlocks', connectionId],
    queryFn: () => api.dpaDeadlocks(connectionId),
    enabled: subTab === 'deadlocks',
    staleTime: 60000,
    refetchInterval: DPA_SLOW_REFETCH_MS,
  });
  const blockers = useQuery({
    queryKey: ['dpa-blocking-top-blockers', connectionId],
    queryFn: () => api.dpaBlockingTopBlockers(connectionId, '7d'),
    enabled: subTab === 'blockers',
    staleTime: 60000,
    refetchInterval: DPA_SLOW_REFETCH_MS,
  });
  const heatmap = useQuery({
    queryKey: ['dpa-blocking-heatmap', connectionId],
    queryFn: () => api.dpaBlockingHeatmap(connectionId, '7d'),
    enabled: subTab === 'heatmap',
    staleTime: 60000,
    refetchInterval: DPA_SLOW_REFETCH_MS,
  });
  const records: any[] = history.data?.records ?? [];
  const deadlockEvents: any[] = deadlocks.data ?? [];
  const DOW = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  return (
    <div className="space-y-3">
      <div className="flex gap-1 flex-wrap items-center">
        {(['live', 'history', 'deadlocks', 'blockers', 'heatmap'] as const).map((t) => (
          <button key={t} type="button" className={`nv-btn !text-2xs ${subTab === t ? 'bg-sky-900/40 text-sky-300' : ''}`}
            onClick={() => setSubTab(t)}>
            {t === 'live' ? 'Live' : t === 'history' ? 'History' : t === 'deadlocks' ? 'Deadlocks' : t === 'blockers' ? 'Top Blockers' : 'Heatmap'}
          </button>
        ))}
        <AiAnalysisButton
          connectionId={connectionId}
          kind="blocking"
          identifier="blocking"
          title="Análisis con IA — Blocking"
          titleAttr="Analizar cadenas de blocking con IA (RCA y recomendaciones)"
        />
      </div>
      {subTab === 'live' && <BlockingPanel data={data} />}
      {subTab === 'history' && (
        <div className="space-y-2">
          <div className="flex items-center justify-between">
            <span className="text-2xs text-nv-textMuted">{records.length} blocking incidents</span>
            <ExportMenu rows={records.map((e) => ({
              id: e.id, status: e.isActive ? 'active' : 'closed',
              startedAt: e.startedAt ?? '', blockerPid: e.blockerPid,
              blockerUser: e.blockerUser ?? '', victimCount: e.victimCount,
              durationSec: e.durationSec ?? '', blockerSql: e.blockerSql ?? '',
            }))} filename="dpa-blocking-history" />
          </div>
          <div className="space-y-1 max-h-96 overflow-auto">
            {history.isLoading && <Loading />}
            {!history.isLoading && records.length === 0 && <Empty msg="No blocking history recorded." />}
            {records.map((e: any) => (
              <div key={e.id} className="px-2 py-2 rounded border border-nv-border/40 bg-nv-surface/30">
                <div className="flex items-center gap-2">
                  <span className={`text-2xs font-medium ${e.isActive ? 'text-orange-400' : 'text-nv-textMuted'}`}>
                    {e.isActive ? '🔴 ACTIVE' : '✓ closed'}
                  </span>
                  <span className="text-2xs text-nv-textSubtle ml-auto">{e.startedAt ? new Date(e.startedAt).toLocaleString() : ''}</span>
                </div>
                <p className="text-[10px] text-nv-textMuted">PID {e.blockerPid} · {e.blockerUser ?? '—'} · {e.victimCount} victims
                  {e.durationSec != null ? ` · ${Math.round(e.durationSec)}s` : ''}</p>
                {e.blockerSql && <p className="text-[10px] font-mono text-nv-textSubtle truncate mt-1">{e.blockerSql}</p>}
              </div>
            ))}
          </div>
        </div>
      )}
      {subTab === 'deadlocks' && (
        <div className="space-y-2">
          <div className="flex items-center justify-between">
            <span className="text-2xs text-nv-textMuted">{deadlockEvents.length} deadlock events</span>
            <ExportMenu rows={deadlockEvents.map((e, i) => ({
              index: i, timestamp: e.timestamp ?? '',
              excerpt: e.payload?.excerpt ?? JSON.stringify(e.payload ?? {}),
            }))} filename="dpa-deadlocks" />
          </div>
          <div className="space-y-1 max-h-96 overflow-auto">
            {deadlocks.isLoading && <Loading />}
            {!deadlocks.isLoading && deadlockEvents.length === 0 && <Empty msg="No deadlocks recorded yet." />}
            {deadlockEvents.map((e: any, i: number) => (
              <div key={i} className="px-2 py-2 rounded border border-red-900/40 bg-red-950/20">
                <div className="flex items-center gap-2 mb-1">
                  <span className="text-2xs font-semibold text-red-400">💀 deadlock</span>
                  <span className="text-2xs text-nv-textSubtle ml-auto">{e.timestamp ? new Date(e.timestamp).toLocaleString() : ''}</span>
                </div>
                <pre className="text-[10px] font-mono text-nv-textMuted whitespace-pre-wrap max-h-40 overflow-auto">
                  {e.payload?.excerpt ?? JSON.stringify(e.payload ?? {}, null, 2)}
                </pre>
              </div>
            ))}
          </div>
        </div>
      )}
      {subTab === 'blockers' && (
        <div className="space-y-2">
          <div className="flex items-center justify-between">
            <span className="text-2xs text-nv-textMuted">Top blockers (7d)</span>
            <ExportMenu rows={(blockers.data?.blockers ?? []).map((b: any) => ({
              user: b.blockerUser ?? '', incidents: b.incidents,
              totalDurationSec: b.totalDurationSec ?? 0, sql: b.blockerSql ?? '',
            }))} filename="dpa-top-blockers" />
          </div>
          <div className="overflow-auto">
            {blockers.isLoading && <Loading />}
            {!blockers.isLoading && !(blockers.data?.blockers?.length) && <Empty msg="No blocking incidents in window." />}
            <table className="w-full text-2xs">
              <thead><tr className="text-nv-textMuted border-b border-nv-border">
                <th className="text-left py-1">User</th><th className="text-left py-1">SQL</th>
                <th className="text-right py-1">Incidents</th><th className="text-right py-1">Duration</th>
              </tr></thead>
              <tbody>
                {(blockers.data?.blockers ?? []).map((b: any, i: number) => (
                  <tr key={i} className="border-b border-nv-border/40">
                    <td className="py-1">{b.blockerUser}</td>
                    <td className="py-1 font-mono truncate max-w-xs">{b.blockerSql}</td>
                    <td className="py-1 text-right">{b.incidents}</td>
                    <td className="py-1 text-right">{Math.round(Number(b.totalDurationSec ?? 0))}s</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
      {subTab === 'heatmap' && (
        <div>
          {heatmap.isLoading && <Loading />}
          {!heatmap.isLoading && (
            <div className="overflow-x-auto">
              <table className="text-[10px] border-collapse">
                <thead><tr><th className="p-1" /><th className="p-1">Hour →</th></tr></thead>
                <tbody>
                  {DOW.map((d, dow) => (
                    <tr key={d}>
                      <td className="p-1 text-nv-textMuted pr-2">{d}</td>
                      <td className="p-0">
                        <div className="flex">
                          {Array.from({ length: 24 }, (_, hour) => {
                            const cell = (heatmap.data?.cells ?? []).find((c: any) => c.dow === dow && c.hour === hour);
                            const count = cell?.count ?? 0;
                            const max = heatmap.data?.maxCount ?? 1;
                            const alpha = count > 0 ? 0.2 + (count / max) * 0.8 : 0.05;
                            return <div key={hour} title={`${d} ${hour}:00 — ${count}`}
                              className="w-3 h-3 border border-nv-border/20"
                              style={{ background: `rgba(249, 115, 22, ${alpha})` }} />;
                          })}
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      )}
    </div>
  );
}
